import type { LevelGameConfig } from "../levelGameConfig.js";
import {
  arc1DockingDefault,
  buildArc1Layout,
  FLOOR_STEP_SIM,
} from "../levelShared.js";
import { levels2to5Common, paxH } from "./levels2to5Common.js";

/** Irregular: one 320 sim gap (480 → 800). */
const level3Floors: readonly number[] = [
  0,
  FLOOR_STEP_SIM,
  2 * FLOOR_STEP_SIM,
  3 * FLOOR_STEP_SIM,
  5 * FLOOR_STEP_SIM, // 800: gap after 480
  6 * FLOOR_STEP_SIM,
  7 * FLOOR_STEP_SIM,
  8 * FLOOR_STEP_SIM,
];

const level3Layout = buildArc1Layout(level3Floors, {
  extentMaxAltitude: 1_800,
  gravityBlendStartAltitude: 550,
  gravityBlendEndAltitude: 1_650,
});

const game: Omit<LevelGameConfig, keyof typeof level3Layout> = {
  ...levels2to5Common,
  ...arc1DockingDefault,
  passengerHeightSim: paxH,
  allowedPassengerTypes: ["regular", "urgent", "heavy"],
  initialPassengerCount: 20,
  maxWaitingPerFloor: 4,
  passengerSpawnIntervalSeconds: 1.9,
  scoreAttackTimerSeconds: 100,
  star1MinScore: 200,
  star2MinScore: 420,
  star3MinScore: 800,
  groundCrashEndsRun: false,
  campaignId: 3,
  displayName: "The long climb",
};

export const level3Game: LevelGameConfig = {
  ...level3Layout,
  ...game,
};
