import type { LevelGameConfig } from "./levelGameConfig.js";
import { defaultPhysicsConfig, type PhysicsConfig } from "./physics.js";

/**
 * Derive world vertical bounds and extent from a level. Single place so multiple levels
 * cannot drift from `defaultPhysicsConfig` (see `.cursorrules` portability).
 */
export function makePhysicsForLevel(
  l: Pick<
    LevelGameConfig,
    | "extentMaxAltitude"
    | "floorAltitudes"
    | "floorSlabSim"
    | "elevatorCabHeightSim"
  >,
): PhysicsConfig {
  return {
    ...defaultPhysicsConfig,
    levelMaxAltitude: l.extentMaxAltitude,
    worldMinAltitude:
      l.floorAltitudes[0]! + l.floorSlabSim + l.elevatorCabHeightSim / 2,
  };
}
