import type { LevelGameConfig } from "../config/levelGameConfig.js";
import {
  DEBOARD_LOBBY_SEGMENT_FRAC,
  TRANSFER_DEATH_ECHO_SECONDS,
} from "../config/transferTiming.js";
import type {
  FloorIdleState,
  GameSimState,
  TransferDeathEcho,
  UrgentWaitWalkoff,
} from "./gameState.js";
import { clampRunScore } from "./scoreAttack.js";
import type { Passenger, Transfer } from "./passenger.js";
import { totalElevatorMass } from "./passenger.js";
import {
  findDockableFloorIndex,
  inHoverBand,
  velocityStable,
} from "./docking.js";

function stayersLoad(
  onboard: readonly Passenger[],
  floorIndex: number,
): { w: number; c: number } {
  let w = 0;
  let c = 0;
  for (const p of onboard) {
    if (p.targetFloorIndex !== floorIndex) {
      w += p.weight;
      c += 1;
    }
  }
  return { w, c };
}

/** Greedy FIFO from `waiting` (PRD §4.4). */
export function selectPendingBoarders(
  waiting: readonly Passenger[],
  onboard: readonly Passenger[],
  floorIndex: number,
  level: LevelGameConfig,
): Passenger[] {
  const { w, c } = stayersLoad(onboard, floorIndex);
  let wAvail = level.maxPassengerWeight - w;
  let cAvail = level.maxPassengersOnboard - c;
  const out: Passenger[] = [];
  for (const p of waiting) {
    if (p.weight <= wAvail && cAvail > 0) {
      out.push(p);
      wAvail -= p.weight;
      cAvail -= 1;
    }
  }
  return out;
}

function hasTransferWorkAtFloor(
  floorIndex: number,
  onboard: readonly Passenger[],
  waitingByFloor: Passenger[][],
  level: LevelGameConfig,
): boolean {
  if (onboard.some((p) => p.targetFloorIndex === floorIndex)) {
    return true;
  }
  return (
    selectPendingBoarders(
      waitingByFloor[floorIndex] ?? [],
      onboard,
      floorIndex,
      level,
    ).length > 0
  );
}

function tickUrgentWaiting(
  waitingByFloor: Passenger[][],
  dt: number,
): { waitingByFloor: Passenger[][]; newWalkoffs: UrgentWaitWalkoff[] } {
  const newWalkoffs: UrgentWaitWalkoff[] = [];
  const outFloors = waitingByFloor.map((queue, floorIndex) => {
    const nextQueue: Passenger[] = [];
    for (let queueIndex = 0; queueIndex < queue.length; queueIndex += 1) {
      const p = queue[queueIndex]!;
      if (p.archetype !== "urgent" || p.urgencyTimerSeconds === undefined) {
        nextQueue.push(p);
        continue;
      }
      const rem = p.urgencyTimerSeconds - dt;
      if (rem > 0) {
        nextQueue.push({ ...p, urgencyTimerSeconds: rem });
      } else {
        const durationSeconds =
          p.transferDurationSeconds * (1 - DEBOARD_LOBBY_SEGMENT_FRAC);
        newWalkoffs.push({
          floorIndex,
          queueIndex,
          passenger: { ...p, urgencyTimerSeconds: 0 },
          progress: 0,
          durationSeconds,
        });
      }
    }
    return nextQueue;
  });
  return { waitingByFloor: outFloors, newWalkoffs };
}

function removePassengerIdsFromFloor(
  waitingByFloor: Passenger[][],
  floorIndex: number,
  ids: ReadonlySet<number>,
): Passenger[][] {
  return waitingByFloor.map((q, i) =>
    i === floorIndex ? q.filter((p) => !ids.has(p.id)) : q.slice(),
  );
}

function advanceTransfers(
  transfers: readonly Transfer[],
  dt: number,
  kind: "deboard" | "board",
  onboard: readonly Passenger[],
): {
  remaining: Transfer[];
  onboard: Passenger[];
  scoreDelta: number;
  /** Passengers whose boarding transfer just finished this step (board kind only). */
  boardJustCompleted: Passenger[];
} {
  let scoreDelta = 0;
  const remaining: Transfer[] = [];
  const ob = onboard.slice();
  const boardJustCompleted: Passenger[] = [];
  for (const t of transfers) {
    const prog = t.progress + dt / t.passenger.transferDurationSeconds;
    if (prog >= 1) {
      if (kind === "deboard") {
        const idx = ob.findIndex((p) => p.id === t.passenger.id);
        if (idx >= 0) {
          ob.splice(idx, 1);
        }
        scoreDelta += t.passenger.scoreValue;
      } else {
        ob.push(t.passenger);
        boardJustCompleted.push(t.passenger);
      }
    } else {
      remaining.push({ ...t, progress: prog });
    }
  }
  return { remaining, onboard: ob, scoreDelta, boardJustCompleted };
}

function idleFloor(): FloorIdleState {
  return { tag: "idle", hoverFloor: null, stableHoverSec: 0 };
}

/**
 * After physics: hover accumulation, doors, boarding order (deboard first), grace kills, door idle close.
 * Order is documented in IMPLEMENTATION.md (physics then floor interaction).
 */
export function stepFloorInteraction(
  state: GameSimState,
  level: LevelGameConfig,
  baseMass: number,
  dt: number,
): GameSimState {
  const el = state.elevator;
  const tickUrgent = tickUrgentWaiting(
    state.waitingByFloor.map((q) => q.slice()),
    dt,
  );
  let waitingByFloor = tickUrgent.waitingByFloor;
  const walkoffsThisStep = tickUrgent.newWalkoffs;
  const mergedWalkoffs = [...state.urgentWaitWalkoffs, ...walkoffsThisStep];
  let onboard = state.onboard.slice();
  let runScore = state.runScore;
  let floor = state.floor;
  let teachBlock = state.teachBlockGroundSpawns;
  let teachEarned = state.teachEarnedNonGroundDock;

  if (floor.tag === "idle") {
    const aligned = findDockableFloorIndex(el.altitude, el.velocity, level);
    let hoverFloor = floor.hoverFloor;
    let stableHoverSec = floor.stableHoverSec;
    if (aligned === null) {
      hoverFloor = null;
      stableHoverSec = 0;
    } else if (!hasTransferWorkAtFloor(aligned, onboard, waitingByFloor, level)) {
      hoverFloor = aligned;
      stableHoverSec = 0;
    } else if (aligned !== hoverFloor) {
      hoverFloor = aligned;
      stableHoverSec = dt;
    } else {
      stableHoverSec += dt;
    }

    if (
      stableHoverSec >= level.stableHoverSeconds &&
      hoverFloor !== null
    ) {
      const fi = hoverFloor;
      const deboarding: Transfer[] = onboard
        .filter((p) => p.targetFloorIndex === fi)
        .map((p) => ({ passenger: p, kind: "deboard" as const, progress: 0 }));
      const pendingBoard = selectPendingBoarders(
        waitingByFloor[fi] ?? [],
        onboard,
        fi,
        level,
      );
      const hasTransferWork =
        deboarding.length > 0 || pendingBoard.length > 0;
      if (!hasTransferWork) {
        stableHoverSec = 0;
        floor = { tag: "idle", hoverFloor, stableHoverSec };
      } else {
        const boardingStarted = deboarding.length === 0;
        const boarding: Transfer[] = boardingStarted
          ? pendingBoard.map((p) => ({
              passenger: p,
              kind: "board" as const,
              progress: 0,
            }))
          : [];
        const pendingRemainder = boardingStarted ? [] : pendingBoard;
        if (boardingStarted && pendingBoard.length > 0) {
          const ids = new Set(pendingBoard.map((p) => p.id));
          waitingByFloor = removePassengerIdsFromFloor(waitingByFloor, fi, ids);
        }
        floor = {
          tag: "doorsOpen",
          floorIndex: fi,
          graceOutSec: 0,
          deboarding,
          boarding,
          pendingBoard: pendingRemainder,
          boardingStarted,
          doorIdleSec: 0,
        };
        if (
          level.teachBlockGroundSpawnsAfterFirstBoardUntilNonGroundDock ===
            true &&
          fi > 0
        ) {
          teachEarned = true;
          teachBlock = false;
        }
      }
    } else {
      floor = { tag: "idle", hoverFloor, stableHoverSec };
    }

    const mass = totalElevatorMass(baseMass, onboard);
    return {
      ...state,
      waitingByFloor,
      onboard,
      floor,
      runScore: clampRunScore(runScore),
      elevator: { ...el, mass },
      urgentWaitWalkoffs: mergedWalkoffs,
      teachBlockGroundSpawns: teachBlock,
      teachEarnedNonGroundDock: teachEarned,
    };
  }

  // doorsOpen
  const fi = floor.floorIndex;
  const inBand =
    inHoverBand(el.altitude, fi, level) && velocityStable(el.velocity, level);
  const hadTransfers =
    floor.deboarding.length > 0 || floor.boarding.length > 0;
  let graceOutSec = floor.graceOutSec;
  if (hadTransfers) {
    graceOutSec = inBand ? 0 : graceOutSec + dt;
  } else {
    graceOutSec = 0;
  }

  if (graceOutSec > level.hoverBreakGraceSeconds) {
    const deboarding = floor.deboarding;
    const boarding = floor.boarding;
    const deboardingIds = new Set(deboarding.map((t) => t.passenger.id));
    const staticOnboardCountAtDeath = onboard.filter(
      (p) => !deboardingIds.has(p.id),
    ).length;
    const totalOnboardAtDeath = onboard.length;
    const boardingCountAtDeath = boarding.length;

    let killPenalty = 0;
    const penalizedIds = new Set<number>();
    for (const t of deboarding) {
      const id = t.passenger.id;
      if (penalizedIds.has(id)) {
        continue;
      }
      penalizedIds.add(id);
      killPenalty += 0.5 * t.passenger.scoreValue;
    }
    for (const t of boarding) {
      const id = t.passenger.id;
      if (penalizedIds.has(id)) {
        continue;
      }
      penalizedIds.add(id);
      killPenalty += 0.5 * t.passenger.scoreValue;
    }

    const newEchoes: TransferDeathEcho[] = [];
    const dur = TRANSFER_DEATH_ECHO_SECONDS;
    for (let di = 0; di < deboarding.length; di += 1) {
      const t = deboarding[di]!;
      const slotIdx = onboard.findIndex((x) => x.id === t.passenger.id);
      newEchoes.push({
        remainingSec: dur,
        passenger: t.passenger,
        floorIndex: fi,
        kind: "deboard",
        progress: t.progress,
        transferIndex: slotIdx >= 0 ? slotIdx : di,
        staticOnboardCountAtDeath,
        boardingCountAtDeath,
        totalOnboardAtDeath,
      });
    }
    for (let bi = 0; bi < boarding.length; bi += 1) {
      const t = boarding[bi]!;
      newEchoes.push({
        remainingSec: dur,
        passenger: t.passenger,
        floorIndex: fi,
        kind: "board",
        progress: t.progress,
        transferIndex: bi,
        staticOnboardCountAtDeath,
        boardingCountAtDeath,
        totalOnboardAtDeath,
      });
    }

    const deadDeboardIds = new Set(deboarding.map((t) => t.passenger.id));
    onboard = onboard.filter((p) => !deadDeboardIds.has(p.id));
    const mass = totalElevatorMass(baseMass, onboard);
    return {
      ...state,
      waitingByFloor,
      onboard,
      runScore: clampRunScore(runScore - killPenalty),
      floor: idleFloor(),
      elevator: { ...el, mass },
      transferDeathEchoes: [...state.transferDeathEchoes, ...newEchoes],
      urgentWaitWalkoffs: mergedWalkoffs,
      teachBlockGroundSpawns: teachBlock,
      teachEarnedNonGroundDock: teachEarned,
    };
  }

  let deboarding = floor.deboarding;
  let boarding = floor.boarding;
  let pendingBoard = floor.pendingBoard;
  let boardingStarted = floor.boardingStarted;
  let doorIdleSec = floor.doorIdleSec;

  if (deboarding.length > 0) {
    const adv = advanceTransfers(deboarding, dt, "deboard", onboard);
    deboarding = adv.remaining;
    onboard = adv.onboard;
    runScore = clampRunScore(runScore + adv.scoreDelta);
  }

  if (deboarding.length === 0 && !boardingStarted) {
    boardingStarted = true;
    boarding = pendingBoard.map((p) => ({
      passenger: p,
      kind: "board" as const,
      progress: 0,
    }));
    if (pendingBoard.length > 0) {
      const ids = new Set(pendingBoard.map((p) => p.id));
      waitingByFloor = removePassengerIdsFromFloor(waitingByFloor, fi, ids);
    }
    pendingBoard = [];
  }

  if (boarding.length > 0) {
    const adv = advanceTransfers(boarding, dt, "board", onboard);
    boarding = adv.remaining;
    onboard = adv.onboard;
    runScore = clampRunScore(runScore + adv.scoreDelta);
    if (
      level.teachBlockGroundSpawnsAfterFirstBoardUntilNonGroundDock === true &&
      !teachEarned &&
      fi === 0 &&
      adv.boardJustCompleted.length > 0
    ) {
      teachBlock = true;
    }
  }

  if (
    deboarding.length === 0 &&
    boarding.length === 0 &&
    boardingStarted
  ) {
    doorIdleSec += dt;
    if (doorIdleSec >= level.doorAutoCloseIdleSeconds) {
      floor = idleFloor();
    } else {
      floor = {
        tag: "doorsOpen",
        floorIndex: fi,
        graceOutSec,
        deboarding,
        boarding,
        pendingBoard,
        boardingStarted,
        doorIdleSec,
      };
    }
  } else {
    floor = {
      tag: "doorsOpen",
      floorIndex: fi,
      graceOutSec,
      deboarding,
      boarding,
      pendingBoard,
      boardingStarted,
      doorIdleSec,
    };
  }

  const mass = totalElevatorMass(baseMass, onboard);
  return {
    ...state,
    waitingByFloor,
    onboard,
    floor,
    runScore: clampRunScore(runScore),
    elevator: { ...el, mass },
    urgentWaitWalkoffs: mergedWalkoffs,
    teachBlockGroundSpawns: teachBlock,
    teachEarnedNonGroundDock: teachEarned,
  };
}
