/**
 * Dormant native bridge stub for future shells.
 * Current MVP target is Vite/web; this module is safe to keep imported because browser/dev
 * hosts no-op when no native bridge is bound.
 *
 * `NativeGameBridge` — one JSON message schema for iOS (WKWebView) and Android (WebView + `@JavascriptInterface`).
 * - iOS: `webkit.messageHandlers.nativeGameBridge.postMessage(plainObject)` (clones the object into a NSDictionary in Swift).
 * - Android: `NativeGameBridge.postMessage(stringified JSON)`.
 * - Web / dev: no bridge → no-ops.
 */
export const NATIVE_WEBKIT_HANDLER_NAME = "nativeGameBridge" as const;

export const NATIVE_MESSAGE_SCHEMA_VERSION = 1 as const;

export type GameToNativeMessage =
  | {
      v: 1;
      type: "levelComplete";
      campaignId: number;
      levelId: string;
      displayName: string;
      score: number;
      stars: 1 | 2 | 3;
    }
  | {
      v: 1;
      type: "gameOver";
      reason: "bounds" | "timeNoStar" | "groundCrash";
      levelId: string;
      displayName: string;
      score: number;
    }
  | {
      v: 1;
      type: "haptic";
      style: "light" | "medium" | "heavy" | "success" | "warning" | "error";
    }
  | {
      v: 1;
      type: "log";
      message: string;
      level: "debug" | "info" | "warn";
    };

export function encodeGameToNativeJson(m: GameToNativeMessage): string {
  return JSON.stringify(m);
}

type WebKitHandlers = {
  postMessage: (body: object) => void;
};

type GlobalWithWebKit = typeof globalThis & {
  webkit?: { messageHandlers?: Record<string, WebKitHandlers | undefined> };
  /** Injected on Android: `addJavascriptInterface(NativeGameBridge(), "NativeGameBridge")`. */
  NativeGameBridge?: { postMessage: (json: string) => void };
};

/**
 * Forwards the message to the host WebView. Safe in browser dev: no-ops if nothing is bound.
 */
export function postGameToNative(message: GameToNativeMessage): void {
  if (message.v !== NATIVE_MESSAGE_SCHEMA_VERSION) {
    return;
  }
  const g = globalThis as GlobalWithWebKit;
  const h = g.webkit?.messageHandlers?.[NATIVE_WEBKIT_HANDLER_NAME];
  if (h?.postMessage) {
    h.postMessage(
      JSON.parse(encodeGameToNativeJson(message)) as object,
    );
    return;
  }
  if (g.NativeGameBridge && typeof g.NativeGameBridge.postMessage === "function") {
    g.NativeGameBridge.postMessage(encodeGameToNativeJson(message));
  }
}
