export type LevelEntryTrigger =
  | "menuStart"
  | "retry"
  | "retryComplete"
  | "nextLevel";

export type LevelEntryPlan = {
  runPhase: "play" | "doorOpen";
  showAmbient: boolean;
  animateDoorIntro: boolean;
};

export function planLevelEntry(
  _trigger: LevelEntryTrigger,
  prefersReducedMotion: boolean,
): LevelEntryPlan {
  if (prefersReducedMotion) {
    return {
      runPhase: "play",
      showAmbient: false,
      animateDoorIntro: false,
    };
  }
  return {
    runPhase: "doorOpen",
    showAmbient: true,
    animateDoorIntro: true,
  };
}
