import type { LevelGameConfig } from "../config/levelGameConfig.js";

/**
 * Cab center altitude when aligned with floor `floorIndex`: cab bottom on slab top
 * (`fa + floorSlabSim`), same convention as level `startAltitude` on the lowest floor.
 */
export function floorDockCenterAltitude(
  floorIndex: number,
  level: Pick<
    LevelGameConfig,
    "floorAltitudes" | "elevatorCabHeightSim" | "floorSlabSim"
  >,
): number {
  const fa = level.floorAltitudes[floorIndex];
  if (fa === undefined) {
    return 0;
  }
  return fa + level.floorSlabSim + level.elevatorCabHeightSim / 2;
}

/**
 * Vertical hover band for a floor: from structural floor base (`fa`, bottom of slab)
 * through lobby ceiling (`fa + floorSlabSim + lobbyHeightSim`).
 */
export function floorHoverBandAltitudes(
  floorIndex: number,
  level: Pick<
    LevelGameConfig,
    "floorAltitudes" | "floorSlabSim" | "lobbyHeightSim"
  >,
): { low: number; high: number } | null {
  const fa = level.floorAltitudes[floorIndex];
  if (fa === undefined) {
    return null;
  }
  const low = fa;
  const high = fa + level.floorSlabSim + level.lobbyHeightSim;
  return { low, high };
}

export function inHoverBand(
  altitude: number,
  floorIndex: number,
  level: LevelGameConfig,
): boolean {
  const band = floorHoverBandAltitudes(floorIndex, level);
  if (!band) {
    return false;
  }
  return altitude >= band.low && altitude <= band.high;
}

export function velocityStable(
  velocity: number,
  level: Pick<LevelGameConfig, "dockingVelocityThreshold">,
): boolean {
  return Math.abs(velocity) < level.dockingVelocityThreshold;
}

/**
 * Floor index if cab is in hover band and motion is calm enough to accumulate stable hover.
 */
export function findDockableFloorIndex(
  altitude: number,
  velocity: number,
  level: LevelGameConfig,
): number | null {
  if (!velocityStable(velocity, level)) {
    return null;
  }
  let best: { i: number; dist: number } | null = null;
  for (let i = 0; i < level.floorAltitudes.length; i += 1) {
    if (!inHoverBand(altitude, i, level)) {
      continue;
    }
    const center = floorDockCenterAltitude(i, level);
    const dist = Math.abs(altitude - center);
    if (!best || dist < best.dist) {
      best = { i, dist };
    }
  }
  return best ? best.i : null;
}
