import type { LevelGameConfig } from "../config/levelGameConfig.js";
import type { PassengerArchetypeMvp } from "../sim/passenger.js";
import { passengerArchetypeMvpBaseScore } from "../sim/passenger.js";

const DISPLAY_NAME: Record<PassengerArchetypeMvp, string> = {
  regular: "Regular",
  urgent: "Urgent",
  heavy: "Heavy",
};

/**
 * Order for the HUD legend: highest delivery points first.
 */
export function sortArchetypesByScoreDesc(
  types: readonly PassengerArchetypeMvp[],
): PassengerArchetypeMvp[] {
  return [...types].sort(
    (a, b) => passengerArchetypeMvpBaseScore[b] - passengerArchetypeMvpBaseScore[a],
  );
}

export function clearPassengerTypeLegend(root: HTMLElement): void {
  root.replaceChildren();
}

/**
 * Renders one row per allowed archetype on the current level, points descending.
 */
export function updatePassengerTypeLegend(
  root: HTMLElement,
  level: LevelGameConfig,
): void {
  clearPassengerTypeLegend(root);
  const title = document.createElement("span");
  title.className = "hud-cab-destinations-title";
  title.textContent = "Passenger types";
  root.appendChild(title);
  const ordered = sortArchetypesByScoreDesc(level.allowedPassengerTypes);
  for (const arch of ordered) {
    const row = document.createElement("span");
    row.className = "hud-legend-item";
    const sw = document.createElement("span");
    sw.className = `hud-legend-swatch hud-legend-swatch--${arch}`;
    const pts = document.createElement("span");
    pts.className = "hud-legend-pts";
    pts.setAttribute("aria-hidden", "true");
    pts.textContent = `+${passengerArchetypeMvpBaseScore[arch]}`;
    row.appendChild(sw);
    row.appendChild(document.createTextNode(DISPLAY_NAME[arch]));
    row.appendChild(pts);
    root.appendChild(row);
  }
}
