/** MVP archetypes (PRD §4.3). */
export type PassengerArchetypeMvp = "regular" | "urgent" | "heavy";

/** Initial waiting patience for urgent passengers (HUD bar denominator). */
export const URGENT_PATIENCE_SECONDS = 45;

export type Passenger = {
  id: number;
  sourceFloorIndex: number;
  targetFloorIndex: number;
  weight: number;
  walkSpeed: number;
  urgencyTimerSeconds?: number;
  /** Set for urgent; equals initial `urgencyTimerSeconds` for bar fill ratio. */
  urgencyPatienceMaxSeconds?: number;
  scoreValue: number;
  archetype: PassengerArchetypeMvp;
  /** Seconds to complete one board or deboard walk (PRD §4.5 ~1–2 s). */
  transferDurationSeconds: number;
};

export type Transfer = {
  passenger: Passenger;
  kind: "deboard" | "board";
  progress: number;
};

export function totalPassengerWeight(onboard: readonly Passenger[]): number {
  let s = 0;
  for (const p of onboard) {
    s += p.weight;
  }
  return s;
}

export function totalElevatorMass(
  baseMass: number,
  onboard: readonly Passenger[],
): number {
  return baseMass + totalPassengerWeight(onboard);
}

/** Per-archetype points on successful drop-off; HUD legend reads from the same table. */
export const passengerArchetypeMvpBaseScore: Readonly<
  Record<PassengerArchetypeMvp, number>
> = {
  regular: 10,
  urgent: 25,
  heavy: 15,
};

const archetypeDefaults: Record<
  PassengerArchetypeMvp,
  { weight: number; walkSpeed: number; transferDurationSeconds: number; scoreValue: number; urgency?: number }
> = {
  regular: {
    weight: 0.12,
    walkSpeed: 1,
    transferDurationSeconds: 1.5,
    scoreValue: passengerArchetypeMvpBaseScore.regular,
  },
  urgent: {
    weight: 0.1,
    walkSpeed: 1.1,
    transferDurationSeconds: 1.2,
    scoreValue: passengerArchetypeMvpBaseScore.urgent,
    urgency: URGENT_PATIENCE_SECONDS,
  },
  heavy: {
    weight: 0.28,
    walkSpeed: 0.85,
    transferDurationSeconds: 2,
    scoreValue: passengerArchetypeMvpBaseScore.heavy,
  },
};

export function createPassenger(
  id: number,
  sourceFloorIndex: number,
  targetFloorIndex: number,
  archetype: PassengerArchetypeMvp,
): Passenger {
  const d = archetypeDefaults[archetype];
  return {
    id,
    sourceFloorIndex,
    targetFloorIndex,
    weight: d.weight,
    walkSpeed: d.walkSpeed,
    scoreValue: d.scoreValue,
    archetype,
    transferDurationSeconds: d.transferDurationSeconds,
    ...(archetype === "urgent" && d.urgency !== undefined
      ? {
          urgencyTimerSeconds: d.urgency,
          urgencyPatienceMaxSeconds: d.urgency,
        }
      : {}),
  };
}
