/**
 * Shared Arc 1 levels 2–5: identical mass/capacity/door auto-close, `passengerHeightSim`, and
 * `floorStair` helper. Level 1 uses `arc1DockingLooseL1` and its own layout instead.
 */
import type { LevelGameConfig } from "../levelGameConfig.js";
import {
  arc1DockingDefault,
  FLOOR_SLAB_SIM,
  FLOOR_STEP_SIM,
  LOBBY_HEIGHT_SIM,
} from "../levelShared.js";

export const paxH = FLOOR_SLAB_SIM + LOBBY_HEIGHT_SIM;

export const floorStair = (nFloors: number) =>
  Array.from({ length: nFloors }, (_, i) => i * FLOOR_STEP_SIM) as number[];

export const levels2to5Common: Pick<
  LevelGameConfig,
  "maxPassengerWeight" | "maxPassengersOnboard" | "doorAutoCloseIdleSeconds"
> = {
  maxPassengerWeight: 1.2,
  maxPassengersOnboard: 8,
  doorAutoCloseIdleSeconds: arc1DockingDefault.doorAutoCloseIdleSeconds,
};
