import { getDevicePixelRatio } from "../hostEnvironment.js";

const marginFrac = 0.08;

export function smoothstep01(t: number): number {
  const x = Math.min(1, Math.max(0, t));
  return x * x * (3 - 2 * x);
}

export function resizeCanvasToDisplaySize(canvas: HTMLCanvasElement): number {
  const dpr = Math.min(2, getDevicePixelRatio() || 1);
  const w = Math.floor(canvas.clientWidth * dpr);
  const h = Math.floor(canvas.clientHeight * dpr);
  if (canvas.width !== w || canvas.height !== h) {
    canvas.width = w;
    canvas.height = h;
  }
  return dpr;
}

/**
 * Map simulation altitude (up positive) to canvas Y (down positive)
 * using a vertical window centered on `cameraCenterAltitude`.
 */
export function worldAltitudeToCanvasY(
  altitude: number,
  cameraCenterAltitude: number,
  viewHalfSim: number,
  canvasHeightCss: number,
): number {
  const span = 2 * viewHalfSim;
  if (span <= 0) {
    return canvasHeightCss / 2;
  }
  const viewBottom = cameraCenterAltitude - viewHalfSim;
  const t = (altitude - viewBottom) / span;
  const usable = 1 - 2 * marginFrac;
  return canvasHeightCss * (1 - marginFrac - t * usable);
}

/**
 * Vertical screen pixels for a sim altitude delta (same linear scale as
 * `worldAltitudeToCanvasY`). Use this for cab / sprite height so sim proportions
 * match what floors and hover bands show.
 */
export function worldAltitudeDeltaToCanvasPx(
  deltaAltitude: number,
  viewHalfSim: number,
  canvasHeightCss: number,
): number {
  const span = 2 * viewHalfSim;
  if (span <= 0) {
    return 0;
  }
  const usable = 1 - 2 * marginFrac;
  return (Math.abs(deltaAltitude) / span) * usable * canvasHeightCss;
}
