/**
 * Altitude-based gravity (PRD §4.8). Returns effective g in sim units / s².
 */
export function effectiveGravity(
  altitude: number,
  baseGravity: number,
  minGravityFactor: number,
  blendStartAltitude: number,
  blendEndAltitude: number,
): number {
  if (blendEndAltitude <= blendStartAltitude) {
    return baseGravity;
  }
  const t =
    (altitude - blendStartAltitude) / (blendEndAltitude - blendStartAltitude);
  const s = Math.max(0, Math.min(1, t));
  const smooth = s * s * (3 - 2 * s);
  return baseGravity * (1 + (minGravityFactor - 1) * smooth);
}
