import { ARC1_CAMPAIGN_LEVELS, getArc1LevelByIndex } from "../config/arc1/campaign.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";
import { createInitialGameState } from "../sim/gameState.js";
import type { GameSimState } from "../sim/gameState.js";
import { clampRunScore, computeStars } from "../sim/scoreAttack.js";
import { runFixedSimulationSteps } from "./gameLoop.js";
import {
  FLOOR_MAX_ZOOM_OUT_FACTOR,
  FLOOR_ZOOM_RAMP_SECONDS,
  shouldApplyFloorCameraZoomIn,
  viewHalfSimFromZoomBlend,
} from "./cameraZoom.js";
import { postGameToNative } from "../bridge/nativeGameBridge.js";
import {
  drawFrame,
  resizeCanvasToDisplaySize,
  type RenderContext,
} from "./render.js";
import {
  getHostTimeMs,
  getHostWindow,
  hostRequestAnimationFrame,
} from "./hostEnvironment.js";
import {
  shouldRunHostGameplay,
  shouldTickTimer,
  type AppScreen,
  type RunPhase,
} from "./runPhaseGates.js";
import {
  planLevelEntry,
  type LevelEntryTrigger,
} from "./levelEntry.js";
import {
  clearCabDestinationsHud,
  updateCabDestinationsHud,
} from "./cabDestinationsHud.js";
import {
  clearPassengerTypeLegend,
  updatePassengerTypeLegend,
} from "./passengerTypeLegendHud.js";

function initialPhysicsAndLevel(
  levelIndex: number,
): { level: LevelGameConfig; physics: PhysicsConfig } {
  const level = getArc1LevelByIndex(levelIndex);
  if (level === undefined) {
    throw new Error(`Invalid campaign level index: ${levelIndex}`);
  }
  return { level, physics: makePhysicsForLevel(level) };
}

let arch1LevelIndex = 0;
let { level: activeLevel, physics: config } = initialPhysicsAndLevel(0);

const canvasDoorFade = {
  start: "game-canvas--door-fade-start",
  fade: "game-canvas--door-fade",
  in: "game-canvas--door-fade-in",
} as const;

function clearGameCanvasDoorFade(): void {
  canvas.classList.remove(
    canvasDoorFade.start,
    canvasDoorFade.fade,
    canvasDoorFade.in,
  );
}

function requireGameCanvas(): HTMLCanvasElement {
  const el = document.querySelector("#game");
  if (!(el instanceof HTMLCanvasElement)) {
    throw new Error("Missing #game canvas");
  }
  return el;
}

function require2dContext(canvas: HTMLCanvasElement): CanvasRenderingContext2D {
  const c = canvas.getContext("2d");
  if (!c) {
    throw new Error("2D context not available");
  }
  return c;
}

function requireEl<T extends HTMLElement>(id: string): T {
  const el = document.querySelector(`#${id}`);
  if (!(el instanceof HTMLElement)) {
    throw new Error(`Missing #${id}`);
  }
  return el as T;
}

const canvas = requireGameCanvas();
const ctx = require2dContext(canvas);

/** iOS WebKit: double-tap can open the text-selection loupe; cancel default touch on the play surface. */
const passiveFalse: AddEventListenerOptions = { passive: false };
function preventTouchDefault(e: Event): void {
  e.preventDefault();
}
for (const type of ["touchstart", "touchend", "touchcancel"] as const) {
  canvas.addEventListener(type, preventTouchDefault, passiveFalse);
}

const screenMenu = requireEl<HTMLDivElement>("screen-menu");
const menuElevatorAmbient = requireEl<HTMLDivElement>("menu-elevator-ambient");
const leftDoor = requireEl<HTMLImageElement>("menu-elevator-door-left");
const DOOR_INTRO_MS = 700;
requireEl<HTMLDivElement>("screen-hud");
const gameHudStack = requireEl<HTMLDivElement>("game-hud-stack");
const screenLevelComplete = requireEl<HTMLDivElement>("screen-level-complete");
const screenGameOver = requireEl<HTMLDivElement>("screen-game-over");
const btnBack = requireEl<HTMLButtonElement>("btn-back");
const btnPause = requireEl<HTMLButtonElement>("btn-pause");
const btnResume = requireEl<HTMLButtonElement>("btn-resume");
const pauseOverlay = requireEl<HTMLDivElement>("pause-overlay");
const btnRetry = requireEl<HTMLButtonElement>("btn-retry");
const btnMenuFromOver = requireEl<HTMLButtonElement>("btn-menu-from-over");
const btnRetryComplete = requireEl<HTMLButtonElement>("btn-retry-complete");
const btnMenuComplete = requireEl<HTMLButtonElement>("btn-menu-complete");
const btnNextLevel = requireEl<HTMLButtonElement>("btn-next-level");
const hudScore = requireEl<HTMLSpanElement>("hud-score");
const hudTimer = requireEl<HTMLSpanElement>("hud-timer");
const hudLevel = requireEl<HTMLSpanElement>("hud-level");
const hudCabDestinations = requireEl<HTMLDivElement>("hud-cab-destinations");
const hudPassengerLegend = requireEl<HTMLDivElement>("hud-passenger-legend");
const resultScore = requireEl<HTMLSpanElement>("result-score");
const resultTuning = requireEl<HTMLParagraphElement>("result-tuning");
const resultLevelName = requireEl<HTMLParagraphElement>("result-level-name");
const resultArcNote = requireEl<HTMLParagraphElement>("result-arc-note");
const resultStarsEl = requireEl<HTMLParagraphElement>("result-stars");
const resultStarSpans = Array.from(
  resultStarsEl.querySelectorAll<HTMLSpanElement>(".result-star"),
);
const levelMenuButtons = [
  requireEl<HTMLButtonElement>("btn-arc1-l1"),
  requireEl<HTMLButtonElement>("btn-arc1-l2"),
  requireEl<HTMLButtonElement>("btn-arc1-l3"),
  requireEl<HTMLButtonElement>("btn-arc1-l4"),
  requireEl<HTMLButtonElement>("btn-arc1-l5"),
] as const;

let screen: AppScreen = "menu";
let runPhase: RunPhase = "menu";
let gameState: GameSimState = createInitialGameState(
  config,
  activeLevel,
  Date.now() >>> 0,
);
let pointerThrust = false;
let spaceThrust = false;
let accumulator = 0;
let lastTime = getHostTimeMs();
let cameraAltitude = activeLevel.startAltitude;
let remainingSeconds = activeLevel.scoreAttackTimerSeconds;
let lastResults: { score: number; stars: 1 | 2 | 3 } | null = null;
/** 0 = zoomed in (near a floor), 1 = zoomed out; ramps over `FLOOR_ZOOM_RAMP_SECONDS` when crossing. */
let shaftZoomBlendT = 0;
/** Bumps when `activeLevel.allowedPassengerTypes` (sorted) changes so the legend re-renders. */
let lastPassengerLegendKey = "";

let doorFinishTimer: ReturnType<typeof setTimeout> | null = null;
function clearDoorFinishTimer(): void {
  if (doorFinishTimer === null) {
    return;
  }
  clearTimeout(doorFinishTimer);
  doorFinishTimer = null;
}

function setCampaignLevelIndex(i: number): void {
  const { level, physics } = initialPhysicsAndLevel(i);
  arch1LevelIndex = i;
  activeLevel = level;
  config = physics;
}

function levelIdForNativeBridge(): string {
  return `arc1-L${arch1LevelIndex + 1}`;
}

function formatTimeLeft(sec: number): string {
  const s = Math.max(0, sec);
  const m = Math.floor(s / 60);
  const r = Math.floor(s % 60);
  return `${m}:${r.toString().padStart(2, "0")}`;
}

function thrustDesired(): boolean {
  return (
    shouldRunHostGameplay(screen, runPhase) && (pointerThrust || spaceThrust)
  );
}

function updateHudDom(): void {
  hudScore.textContent = String(gameState.runScore);
  hudTimer.textContent = formatTimeLeft(remainingSeconds);
  hudLevel.textContent = activeLevel.displayName;
  hudTimer.classList.toggle(
    "hud-timer--low",
    remainingSeconds <= 10 && remainingSeconds > 0,
  );
}

function syncPauseControl(): void {
  if (screen !== "playing") {
    pauseOverlay.hidden = true;
    return;
  }
  // Pause control label stays "Pause" in markup; use overlay + Resume to unpause.
  btnPause.disabled = runPhase === "doorOpen" || runPhase === "paused";
  pauseOverlay.hidden = runPhase !== "paused";
}

function updateLevelCompleteDom(): void {
  if (lastResults === null) {
    return;
  }
  resultScore.textContent = String(lastResults.score);
  resultLevelName.textContent = activeLevel.displayName;
  const n = lastResults.stars;
  for (let i = 0; i < resultStarSpans.length; i += 1) {
    const el = resultStarSpans[i]!;
    const on = i < n;
    el.textContent = on ? "★" : "☆";
    el.classList.toggle("star-on", on);
    el.classList.toggle("star-off", !on);
  }
  resultTuning.textContent = `1★ at ${activeLevel.star1MinScore} · 2★ at ${activeLevel.star2MinScore} · 3★ at ${activeLevel.star3MinScore}`;
  const isLast = arch1LevelIndex >= ARC1_CAMPAIGN_LEVELS.length - 1;
  btnNextLevel.hidden = isLast;
  if (isLast) {
    resultArcNote.textContent = "Arc 1 complete. More campaigns may add new mechanics later.";
    resultArcNote.hidden = false;
  } else {
    resultArcNote.textContent = "";
    resultArcNote.hidden = true;
  }
}

function updateGameOverDom(
  reason: "bounds" | "timeNoStar" | "groundCrash",
): void {
  const h1 = screenGameOver.querySelector("h1");
  const p = screenGameOver.querySelector("p");
  if (!(h1 instanceof HTMLElement) || !(p instanceof HTMLElement)) {
    return;
  }
  if (reason === "bounds") {
    h1.textContent = "Out of bounds";
    p.textContent = "The elevator left the playable area.";
  } else if (reason === "groundCrash") {
    h1.textContent = "Catastrophic landing";
    p.textContent =
      "The cab hit the ground too hard. Everyone aboard was lost.";
  } else {
    h1.textContent = "Time's up";
    const s = clampRunScore(gameState.runScore);
    p.textContent = `Reach at least ${activeLevel.star1MinScore} points (1★) to complete the level. Final score: ${s}.`;
  }
}

function resetLevel(): void {
  gameState = createInitialGameState(
    config,
    activeLevel,
    Date.now() >>> 0,
  );
  remainingSeconds = activeLevel.scoreAttackTimerSeconds;
  lastResults = null;
  accumulator = 0;
  cameraAltitude = activeLevel.startAltitude;
  shaftZoomBlendT = 0;
}

function setScreen(next: AppScreen): void {
  if (next === "menu" || next === "gameOver" || next === "levelComplete") {
    clearDoorFinishTimer();
    leftDoor.removeEventListener("transitionend", onLeftDoorTransformEnd);
  }
  screen = next;
  screenMenu.hidden = next !== "menu";
  gameHudStack.hidden = next !== "playing";
  screenLevelComplete.hidden = next !== "levelComplete";
  screenGameOver.hidden = next !== "gameOver";
  screenMenu.style.pointerEvents = next === "menu" ? "auto" : "none";
  screenLevelComplete.style.pointerEvents =
    next === "levelComplete" ? "auto" : "none";
  screenGameOver.style.pointerEvents = next === "gameOver" ? "auto" : "none";
  if (next === "menu") {
    runPhase = "menu";
    clearGameCanvasDoorFade();
    menuElevatorAmbient.classList.remove("menu-elevator-ambient--open");
    menuElevatorAmbient.hidden = false;
  } else if (next === "levelComplete" || next === "gameOver") {
    runPhase = "play";
    clearGameCanvasDoorFade();
    menuElevatorAmbient.classList.remove("menu-elevator-ambient--open");
    menuElevatorAmbient.hidden = true;
  }
  if (next === "menu" || next === "gameOver" || next === "levelComplete") {
    pointerThrust = false;
    spaceThrust = false;
  }
  if (next !== "playing") {
    lastPassengerLegendKey = "";
    clearPassengerTypeLegend(hudPassengerLegend);
    pauseOverlay.hidden = true;
  }
  if (next === "playing") {
    syncPauseControl();
  }
}

function finishDoorIntro(): void {
  if (runPhase !== "doorOpen" || screen !== "playing") {
    return;
  }
  clearDoorFinishTimer();
  leftDoor.removeEventListener("transitionend", onLeftDoorTransformEnd);
  runPhase = "play";
  clearGameCanvasDoorFade();
  menuElevatorAmbient.classList.remove("menu-elevator-ambient--open");
  menuElevatorAmbient.hidden = true;
  updateHudDom();
  syncPauseControl();
}

function onLeftDoorTransformEnd(this: void, e: Event): void {
  const t = e as TransitionEvent;
  if (e.target !== leftDoor || t.propertyName !== "transform") {
    return;
  }
  finishDoorIntro();
}

function prefersReducedMenuMotion(): boolean {
  const w = getHostWindow();
  return w?.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches
    ? true
    : false;
}

function scheduleFinishDoorIntro(): void {
  clearDoorFinishTimer();
  leftDoor.addEventListener("transitionend", onLeftDoorTransformEnd, {
    passive: true,
  } as AddEventListenerOptions);
  doorFinishTimer = setTimeout(() => {
    doorFinishTimer = null;
    finishDoorIntro();
  }, DOOR_INTRO_MS);
}

function enterConfiguredLevel(trigger: LevelEntryTrigger): void {
  resetLevel();
  const plan = planLevelEntry(trigger, prefersReducedMenuMotion());
  clearGameCanvasDoorFade();
  menuElevatorAmbient.classList.remove("menu-elevator-ambient--open");
  menuElevatorAmbient.hidden = !plan.showAmbient;
  runPhase = plan.runPhase;
  setScreen("playing");
  updateHudDom();
  if (!plan.animateDoorIntro) {
    clearGameCanvasDoorFade();
    return;
  }
  canvas.classList.add(canvasDoorFade.start);
  void menuElevatorAmbient.offsetWidth;
  requestAnimationFrame(() => {
    if (runPhase !== "doorOpen" || screen !== "playing") {
      return;
    }
    canvas.classList.remove(canvasDoorFade.start);
    canvas.classList.add(canvasDoorFade.fade);
    void canvas.offsetWidth;
    canvas.classList.add(canvasDoorFade.in);
    menuElevatorAmbient.classList.add("menu-elevator-ambient--open");
    scheduleFinishDoorIntro();
  });
}

function startCampaignLevel(index: number): void {
  setCampaignLevelIndex(index);
  enterConfiguredLevel("menuStart");
}

for (let i = 0; i < levelMenuButtons.length; i += 1) {
  levelMenuButtons[i]!.addEventListener("click", () => {
    startCampaignLevel(i);
  });
}

btnBack.addEventListener("click", () => {
  setScreen("menu");
});

btnPause.addEventListener("click", () => {
  if (screen !== "playing" || runPhase === "doorOpen" || runPhase === "paused") {
    return;
  }
  runPhase = "paused";
  pointerThrust = false;
  spaceThrust = false;
  syncPauseControl();
});

btnResume.addEventListener("click", () => {
  if (screen === "playing" && runPhase === "paused") {
    runPhase = "play";
    syncPauseControl();
  }
});

btnRetry.addEventListener("click", () => {
  enterConfiguredLevel("retry");
});

btnMenuFromOver.addEventListener("click", () => {
  setScreen("menu");
});

btnRetryComplete.addEventListener("click", () => {
  enterConfiguredLevel("retryComplete");
});

btnMenuComplete.addEventListener("click", () => {
  setScreen("menu");
});

btnNextLevel.addEventListener("click", () => {
  if (arch1LevelIndex < ARC1_CAMPAIGN_LEVELS.length - 1) {
    setCampaignLevelIndex(arch1LevelIndex + 1);
  }
  enterConfiguredLevel("nextLevel");
});

canvas.addEventListener("pointerdown", (e) => {
  if (e.button === 0) {
    pointerThrust = true;
    try {
      canvas.setPointerCapture(e.pointerId);
    } catch {
      /* ignore if capture unsupported */
    }
  }
});
canvas.addEventListener("pointerup", (e) => {
  if (e.button === 0) {
    pointerThrust = false;
  }
});
canvas.addEventListener("pointercancel", () => {
  pointerThrust = false;
});

const appWindow = getHostWindow();
if (appWindow) {
  appWindow.addEventListener(
    "keydown",
    (e) => {
      if (e.code === "Space") {
        e.preventDefault();
        if (shouldRunHostGameplay(screen, runPhase)) {
          spaceThrust = true;
        }
      }
    },
    { passive: false },
  );
  appWindow.addEventListener("keyup", (e) => {
    if (e.code === "Space") {
      spaceThrust = false;
    }
  });

  appWindow.addEventListener("blur", () => {
    pointerThrust = false;
    spaceThrust = false;
  });
}

function updateCamera(
  deltaSeconds: number,
  targetAltitude: number,
  viewHalfSim: number,
): void {
  const smoothing = 10;
  const alpha = 1 - Math.exp(-smoothing * deltaSeconds);
  cameraAltitude += (targetAltitude - cameraAltitude) * alpha;
  const half = viewHalfSim;
  const minCam = config.worldMinAltitude + half;
  const maxCam = config.levelMaxAltitude - half;
  if (maxCam >= minCam) {
    cameraAltitude = Math.max(minCam, Math.min(maxCam, cameraAltitude));
  }
}

/** Keep shaft zoom and camera in sync with live play, without advancing the sim. Used during `doorOpen`. */
function applyPlayingCameraFollow(deltaSeconds: number): void {
  const floorZoomIn = shouldApplyFloorCameraZoomIn(
    gameState.elevator.altitude,
    gameState.elevator.velocity,
    activeLevel,
  );
  const ramp = deltaSeconds / FLOOR_ZOOM_RAMP_SECONDS;
  if (floorZoomIn) {
    shaftZoomBlendT = Math.max(0, shaftZoomBlendT - ramp);
  } else {
    shaftZoomBlendT = Math.min(1, shaftZoomBlendT + ramp);
  }
  const vh = viewHalfSimFromZoomBlend(
    activeLevel.viewHalfSimBase,
    FLOOR_MAX_ZOOM_OUT_FACTOR,
    shaftZoomBlendT,
  );
  updateCamera(deltaSeconds, gameState.elevator.altitude, vh);
  updateHudDom();
}

function frame(now: number): void {
  const deltaMs = now - lastTime;
  lastTime = now;
  const deltaSeconds = Math.min(0.1, deltaMs / 1000);

  if (shouldRunHostGameplay(screen, runPhase)) {
    const loop = runFixedSimulationSteps(gameState, {
      deltaSeconds,
      accumulator,
      physics: config,
      level: activeLevel,
      thrust: thrustDesired(),
    });
    gameState = loop.state;
    accumulator = loop.accumulator;
    if (loop.stopReason === "groundCrashRunEnd") {
      updateGameOverDom("groundCrash");
      postGameToNative({
        v: 1,
        type: "gameOver",
        reason: "groundCrash",
        levelId: levelIdForNativeBridge(),
        displayName: activeLevel.displayName,
        score: clampRunScore(gameState.runScore),
      });
      setScreen("gameOver");
    } else if (loop.stopReason === "bounds") {
      updateGameOverDom("bounds");
      postGameToNative({
        v: 1,
        type: "gameOver",
        reason: "bounds",
        levelId: levelIdForNativeBridge(),
        displayName: activeLevel.displayName,
        score: clampRunScore(gameState.runScore),
      });
      setScreen("gameOver");
    }
    if (screen === "playing" && shouldTickTimer(screen, runPhase)) {
      remainingSeconds -= deltaSeconds;
      if (remainingSeconds <= 0) {
        remainingSeconds = 0;
        const score = clampRunScore(gameState.runScore);
        const stars = computeStars(
          score,
          activeLevel.star1MinScore,
          activeLevel.star2MinScore,
          activeLevel.star3MinScore,
        );
        if (stars >= 1) {
          lastResults = { score, stars: stars as 1 | 2 | 3 };
          updateLevelCompleteDom();
          postGameToNative({
            v: 1,
            type: "levelComplete",
            campaignId: activeLevel.campaignId,
            levelId: levelIdForNativeBridge(),
            displayName: activeLevel.displayName,
            score,
            stars: stars as 1 | 2 | 3,
          });
          setScreen("levelComplete");
        } else {
          lastResults = null;
          updateGameOverDom("timeNoStar");
          postGameToNative({
            v: 1,
            type: "gameOver",
            reason: "timeNoStar",
            levelId: levelIdForNativeBridge(),
            displayName: activeLevel.displayName,
            score: clampRunScore(gameState.runScore),
          });
          setScreen("gameOver");
        }
      } else {
        applyPlayingCameraFollow(deltaSeconds);
      }
    }
  } else if (screen === "playing" && runPhase === "doorOpen") {
    applyPlayingCameraFollow(deltaSeconds);
  }

  const viewHalfSim =
    screen === "playing"
      ? viewHalfSimFromZoomBlend(
          activeLevel.viewHalfSimBase,
          FLOOR_MAX_ZOOM_OUT_FACTOR,
          shaftZoomBlendT,
        )
      : activeLevel.viewHalfSimBase;
  const levelForView = { ...activeLevel, viewHalfSim };

  const dpr = resizeCanvasToDisplaySize(canvas);
  const rc: RenderContext = { canvas, ctx, dpr };
  drawFrame(rc, gameState, levelForView, cameraAltitude, now);
  if (screen === "playing") {
    const legendKey = [...activeLevel.allowedPassengerTypes]
      .slice()
      .sort()
      .join(",");
    if (legendKey !== lastPassengerLegendKey) {
      lastPassengerLegendKey = legendKey;
      updatePassengerTypeLegend(hudPassengerLegend, activeLevel);
    }
    syncPauseControl();
    updateCabDestinationsHud(
      hudCabDestinations,
      gameState,
      activeLevel,
      config.baseMass,
    );
  } else {
    clearCabDestinationsHud(hudCabDestinations);
  }

  hostRequestAnimationFrame(frame);
}

setScreen("menu");
void hostRequestAnimationFrame(frame);
