import type { PhysicsConfig } from "../config/physics.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";
import { createInitialState } from "./elevator.js";
import type { ElevatorState } from "./types.js";
import type { Passenger, Transfer } from "./passenger.js";
import { totalElevatorMass } from "./passenger.js";
import { mulberry32, spawnWaitingByFloor } from "./spawnPassengers.js";

/** Urgent waiting passenger walking off-screen after patience hits zero. */
export type UrgentWaitWalkoff = {
  floorIndex: number;
  /** Index in that floor's queue at expiry (matches waiting render slot). */
  queueIndex: number;
  passenger: Passenger;
  progress: number;
  durationSeconds: number;
};

/** Frozen transfer or in-cab pose for rendering after a passenger kill. */
export type TransferDeathEcho = {
  remainingSec: number;
  passenger: Passenger;
  floorIndex: number;
  kind: "board" | "deboard" | "ground";
  /** Raw progress 0..1 at kill (matches live transfer interpolation). */
  progress: number;
  /** Board: index in boarding array. Deboard: slot in full onboard at death. */
  transferIndex: number;
  staticOnboardCountAtDeath: number;
  boardingCountAtDeath: number;
  totalOnboardAtDeath: number;
};

export type FloorIdleState = {
  tag: "idle";
  hoverFloor: number | null;
  stableHoverSec: number;
};

export type FloorDoorsOpenState = {
  tag: "doorsOpen";
  floorIndex: number;
  graceOutSec: number;
  deboarding: Transfer[];
  boarding: Transfer[];
  pendingBoard: readonly Passenger[];
  boardingStarted: boolean;
  doorIdleSec: number;
};

export type FloorInteractionState = FloorIdleState | FloorDoorsOpenState;

export type GameSimState = {
  elevator: ElevatorState;
  waitingByFloor: Passenger[][];
  onboard: Passenger[];
  floor: FloorInteractionState;
  runScore: number;
  nextPassengerId: number;
  /** Accumulated sim time until next `passengerSpawnIntervalSeconds` spawn attempt. */
  spawnAccumSec: number;
  /** Mulberry32 internal state for runtime passenger spawns (separate stream from initial fill). */
  spawnRngState: number;
  /** Visual-only echoes after failed docking or hard ground impact; stepped in `stepGame`. */
  transferDeathEchoes: TransferDeathEcho[];
  /** Urgent passengers animating out of the lobby after their timer expires. */
  urgentWaitWalkoffs: UrgentWaitWalkoff[];
  /**
   * L1 teach: when true, runtime spawns may not use floor 0 as source (if level flag set).
   * Set true on first full board at floor 0 while `teachEarnedNonGroundDock` is false.
   */
  teachBlockGroundSpawns: boolean;
  /**
   * L1 teach: after opening doors on any non-ground floor, stay true: never re-arm
   * ground block on later ground visits.
   */
  teachEarnedNonGroundDock: boolean;
};

export function createInitialGameState(
  physics: PhysicsConfig,
  level: LevelGameConfig,
  rngSeed: number,
): GameSimState {
  const rng = mulberry32(rngSeed);
  const { waitingByFloor, nextId } = spawnWaitingByFloor(
    {
      floorAltitudes: level.floorAltitudes,
      allowedPassengerTypes: level.allowedPassengerTypes,
      initialPassengerCount: level.initialPassengerCount,
      maxWaitingPerFloor: level.maxWaitingPerFloor,
      ensureWaitingOnFloorsAtStart: level.ensureWaitingOnFloorsAtStart,
    },
    rng,
    1,
  );
  const onboard: Passenger[] = [];
  const mass = totalElevatorMass(physics.baseMass, onboard);
  const elevator: ElevatorState = {
    ...createInitialState(physics, level.startAltitude),
    mass,
  };
  return {
    elevator,
    waitingByFloor,
    onboard,
    floor: { tag: "idle", hoverFloor: null, stableHoverSec: 0 },
    runScore: 0,
    nextPassengerId: nextId,
    spawnAccumSec: 0,
    spawnRngState: (rngSeed ^ 0xa113_c371) >>> 0,
    transferDeathEchoes: [],
    urgentWaitWalkoffs: [],
    teachBlockGroundSpawns: false,
    teachEarnedNonGroundDock: false,
  };
}
