import type { PhysicsConfig } from "../config/physics.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";
import type { GameSimState } from "../sim/gameState.js";
import { stepGame } from "../sim/gameStep.js";
import { effectiveGravity } from "../sim/gravity.js";

/** Stops the fixed-step loop when the run should end in the host (UI). */
export type FixedStepsStopReason = "bounds" | "groundCrashRunEnd";

/**
 * Advance sim by one host frame worth of real time: fixed substeps with spiral-of-death cap.
 * Run-end only when OOB or lethal ground with `groundCrashEndsRun` (see `main.ts` for timer).
 */
export function runFixedSimulationSteps(
  state: GameSimState,
  args: {
    /** Wall-clock seconds to add to the accumulator (already clamped by caller if needed). */
    deltaSeconds: number;
    /** Previous leftover time from the accumulator. */
    accumulator: number;
    physics: PhysicsConfig;
    level: LevelGameConfig;
    thrust: boolean;
  },
): {
  state: GameSimState;
  accumulator: number;
  stopReason: FixedStepsStopReason | null;
} {
  let acc = args.accumulator + args.deltaSeconds;
  const fixed = args.physics.fixedTimestepSeconds;
  let gameState = state;
  let steps = 0;
  let stopReason: FixedStepsStopReason | null = null;
  while (acc >= fixed && steps < args.physics.maxStepsPerFrame) {
    const g = effectiveGravity(
      gameState.elevator.altitude,
      args.physics.gravity,
      args.physics.minGravityFactor,
      args.level.gravityBlendStartAltitude,
      args.level.gravityBlendEndAltitude,
    );
    const step = stepGame(
      gameState,
      args.thrust,
      args.physics,
      args.level,
      g,
      fixed,
    );
    gameState = step.state;
    acc -= fixed;
    steps += 1;
    if (step.lethalGroundImpact && args.level.groundCrashEndsRun) {
      stopReason = "groundCrashRunEnd";
      break;
    }
    if (gameState.elevator.altitude > args.level.failureAltitude) {
      stopReason = "bounds";
      break;
    }
  }
  return { state: gameState, accumulator: acc, stopReason };
}
