export function clampRunScore(score: number): number {
  return Math.max(0, score);
}

/**
 * Star tiers from final score: 0★ below `star1MinScore`, then 1★ / 2★ / 3★ at each threshold.
 */
export function computeStars(
  finalScore: number,
  star1MinScore: number,
  star2MinScore: number,
  star3MinScore: number,
): 0 | 1 | 2 | 3 {
  if (finalScore >= star3MinScore) {
    return 3;
  }
  if (finalScore >= star2MinScore) {
    return 2;
  }
  if (finalScore >= star1MinScore) {
    return 1;
  }
  return 0;
}
