import { domCabDestChipStyle } from "../config/passengerVisual.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";
import type { GameSimState } from "../sim/gameState.js";

/** Passenger weight vs level cap as a percent (rounds; over 100% is possible; UI turns red). */
export function massLoadDisplay(
  totalMass: number,
  baseMass: number,
  maxPassengerWeight: number,
): { percent: number; exceeded: boolean } {
  const w = Math.max(0, totalMass - baseMass);
  if (maxPassengerWeight <= 0) {
    return { percent: 0, exceeded: false };
  }
  const pct = (w / maxPassengerWeight) * 100;
  return {
    percent: Math.round(pct),
    exceeded: w > maxPassengerWeight + 1e-6,
  };
}

/**
 * Right-HUD block under the passenger-type legend: shows onboard destination floor chips.
 */
export function clearCabDestinationsHud(root: HTMLElement): void {
  root.replaceChildren();
}

export function updateCabDestinationsHud(
  root: HTMLElement,
  game: GameSimState,
  level: LevelGameConfig,
  baseMass: number,
): void {
  root.replaceChildren();
  const stats = document.createElement("div");
  stats.className = "hud-cab-destinations-stats";

  const capLine = document.createElement("div");
  capLine.className = "hud-cab-destinations-stats-metric";
  capLine.textContent = `Capacity ${game.onboard.length}/${
    level.maxPassengersOnboard
  }`;
  stats.appendChild(capLine);

  const { percent: massPct, exceeded: massExceeded } = massLoadDisplay(
    game.elevator.mass,
    baseMass,
    level.maxPassengerWeight,
  );
  const massLine = document.createElement("div");
  massLine.className = massExceeded
    ? "hud-cab-destinations-stats-metric hud-cab-destinations-stats-metric--exceeded"
    : "hud-cab-destinations-stats-metric";
  massLine.textContent = `Mass ${massPct}%`;
  stats.appendChild(massLine);

  root.appendChild(stats);

  const title = document.createElement("span");
  title.className = "hud-cab-destinations-title";
  title.textContent = "Cab destinations";
  root.appendChild(title);

  if (game.onboard.length === 0) {
    const empty = document.createElement("span");
    empty.className = "hud-cab-destinations-empty";
    empty.textContent = "— empty —";
    root.appendChild(empty);
    return;
  }

  const sorted = [...game.onboard].sort((a, b) => {
    if (a.targetFloorIndex !== b.targetFloorIndex) {
      return b.targetFloorIndex - a.targetFloorIndex;
    }
    return a.id - b.id;
  });
  const groups: (typeof game.onboard)[] = [];
  for (const p of sorted) {
    const prev = groups[groups.length - 1];
    if (prev && prev[0]!.targetFloorIndex === p.targetFloorIndex) {
      prev.push(p);
    } else {
      groups.push([p]);
    }
  }

  const rows = document.createElement("div");
  rows.className = "hud-cab-destinations-rows";
  for (const group of groups) {
    const row = document.createElement("div");
    row.className = "hud-cab-destinations-row";
    for (let i = 0; i < group.length; i += 1) {
      const p = group[i]!;
      const chip = document.createElement("span");
      chip.className = "hud-cab-dest-chip";
      const c = domCabDestChipStyle(p.archetype);
      chip.style.backgroundColor = c.backgroundColor;
      chip.style.border = c.border;
      chip.style.color = c.color;
      chip.textContent = String(p.targetFloorIndex + 1);
      // Leftmost chip in the stack stays on top; next chips tuck under (narrower run).
      chip.style.zIndex = String(group.length - i);
      row.appendChild(chip);
    }
    rows.appendChild(row);
  }
  root.appendChild(rows);
}
