import { PAX_HEIGHT_FRAC_OF_CAB, PAX_WIDTH_FRAC_OF_CAB } from "../../config/passengerVisual.js";
import { PASSENGER_BODY_FILL, PASSENGER_BODY_STROKE } from "../../config/passengerVisual.js";
import { DEBOARD_LOBBY_SEGMENT_FRAC } from "../../config/transferTiming.js";
import type { TransferDeathEcho, UrgentWaitWalkoff } from "../../sim/gameState.js";
import type { Passenger, PassengerArchetypeMvp } from "../../sim/passenger.js";
import { smoothstep01 } from "./canvasSpace.js";

/**
 * Full Emoji List (unicode.org) row № 39.
 * @see https://unicode.org/emoji/charts/full-emoji-list.html
 */
const PASSENGER_HEAD_SYMBOL_REGULAR = "\u{1F610}";
/** row № 48 (face exhaling) */
const PASSENGER_HEAD_SYMBOL_HEAVY = "\u{1F62E}\u{200D}\u{1F4A8}";
/** row № 104 (face with steam from nose) */
const PASSENGER_HEAD_SYMBOL_URGENT = "\u{1F624}";
/** U+1F480 — skull; see chart “Skull” */
const PASSENGER_HEAD_SYMBOL_DEAD = "\u{1F480}";
/** U+1F628 (fearful face) when |elevator velocity| exceeds threshold (sim units/s, same as HUD speed). */
const PASSENGER_HEAD_SYMBOL_FEARFUL = "\u{1F628}";

/** |cab velocity| above this (sim / s) forces fearful head for all living passengers. */
export const ELEVATOR_HEAD_FEAR_VELOCITY = 50;

export function passengerHeadSymbol(
  archetype: PassengerArchetypeMvp,
  dead: boolean,
  elevatorSpeed?: number,
): string {
  if (dead) {
    return PASSENGER_HEAD_SYMBOL_DEAD;
  }
  if (elevatorSpeed !== undefined) {
    if (Math.abs(elevatorSpeed) > ELEVATOR_HEAD_FEAR_VELOCITY) {
      return PASSENGER_HEAD_SYMBOL_FEARFUL;
    }
  }
  if (archetype === "heavy") {
    return PASSENGER_HEAD_SYMBOL_HEAVY;
  }
  if (archetype === "urgent") {
    return PASSENGER_HEAD_SYMBOL_URGENT;
  }
  return PASSENGER_HEAD_SYMBOL_REGULAR;
}

/** Pixels to lift the patience bar so it clears the head emoji (center on `yTop`; half extends above). */
export function headEmojiReservedAboveBodyPx(s: number): number {
  const maxHeadPx = HEAD_EMOJI_BASE_PX * s * 1.2; // heavy; center on yTop, half above
  return Math.max(0, 4 * s + maxHeadPx * 0.5);
}

export function drawUrgencyBarAbovePassenger(
  ctx: CanvasRenderingContext2D,
  xLeft: number,
  yTopPassenger: number,
  paxW: number,
  remainingSec: number,
  maxSec: number,
  headRoomAboveBodyPx = 0,
): void {
  const barH = 7;
  const gap = 4;
  const barTop = yTopPassenger - headRoomAboveBodyPx - gap - barH;
  const denom = Math.max(1e-4, maxSec);
  const frac = Math.min(1, Math.max(0, remainingSec / denom));
  const inset = 2;
  ctx.fillStyle = "rgba(30, 41, 59, 0.95)";
  ctx.strokeStyle = "rgba(127, 29, 29, 0.9)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.roundRect(xLeft, barTop, paxW, barH, 4);
  ctx.fill();
  ctx.stroke();
  const innerW = Math.max(0, paxW - 2 * inset);
  const fillW = innerW * frac;
  if (fillW > 0) {
    ctx.fillStyle =
      frac < 0.2 ? "rgba(248, 113, 113, 0.95)" : "rgba(251, 191, 36, 0.9)";
    ctx.beginPath();
    ctx.roundRect(xLeft + inset, barTop + inset, fillW, barH - 2 * inset, 3);
    ctx.fill();
  }
}

export type UrgentWalkoffLayoutGeom = {
  cabW: number;
  cabH: number;
  shaftLeft: number;
  queueMargin: number;
  queueGap: number;
  yFeet: number;
  maxPaxHInLobby: number;
};

export function urgentWaitWalkoffLayout(
  geom: UrgentWalkoffLayoutGeom,
  w: UrgentWaitWalkoff,
): { xLeft: number; yTop: number; w: number; h: number } {
  const p = w.passenger;
  const { w: paxW, h: paxH } = paxSizeForCab(
    geom.cabW,
    geom.cabH,
    p.archetype,
    geom.maxPaxHInLobby,
  );
  const xRight =
    geom.shaftLeft -
    geom.queueMargin -
    w.queueIndex * (paxW + geom.queueGap);
  const xLobbyLeft = xRight - paxW;
  const xExit = -paxW - 32;
  const u = smoothstep01(w.progress);
  const xLeft = xLobbyLeft + (xExit - xLobbyLeft) * u;
  const yTop = geom.yFeet - paxH;
  return { xLeft, yTop, w: paxW, h: paxH };
}

export function paxSizeForCab(
  cabW: number,
  cabH: number,
  archetype: Passenger["archetype"],
  maxHeight?: number,
): { w: number; h: number } {
  let w = Math.max(10, cabW * PAX_WIDTH_FRAC_OF_CAB);
  let h = Math.max(20, cabH * PAX_HEIGHT_FRAC_OF_CAB);
  if (archetype === "heavy") {
    w *= 1.14;
    h *= 1.06;
  }
  if (maxHeight !== undefined) {
    h = Math.min(h, maxHeight);
  }
  return { w, h };
}

export function cabSlotCenterX(
  cabLeft: number,
  cabW: number,
  slotIdx: number,
  totalSlots: number,
): number {
  const pad = Math.max(8, cabW * 0.08);
  const inner = Math.max(1, cabW - 2 * pad);
  const n = Math.max(1, totalSlots);
  const step = inner / n;
  return cabLeft + pad + step * (slotIdx + 0.5);
}

export type TransferLayoutGeom = {
  cabW: number;
  cabH: number;
  cabLeft: number;
  cy: number;
  shaftLeft: number;
  queueMargin: number;
  queueGap: number;
  yFeetDock: number;
  maxPaxHDock: number;
};

export function transferPassengerLayout(
  geom: TransferLayoutGeom,
  echo: Pick<
    TransferDeathEcho,
    | "kind"
    | "passenger"
    | "progress"
    | "transferIndex"
    | "staticOnboardCountAtDeath"
    | "boardingCountAtDeath"
    | "totalOnboardAtDeath"
  >,
  groundSplatT = 0,
): { xLeft: number; yTop: number; w: number; h: number } {
  const {
    cabW,
    cabH,
    cabLeft,
    cy,
    shaftLeft,
    queueMargin,
    queueGap,
    yFeetDock,
    maxPaxHDock,
  } = geom;
  const p = echo.passenger;
  const { w: paxW, h: paxH } = paxSizeForCab(cabW, cabH, p.archetype, maxPaxHDock);

  if (echo.kind === "ground") {
    const n = Math.max(1, echo.totalOnboardAtDeath);
    const cx = cabSlotCenterX(
      cabLeft,
      cabW,
      echo.transferIndex,
      n,
    );
    const yBase = cy + cabH / 2 - paxH;
    return {
      xLeft: cx - paxW / 2,
      yTop: yBase + groundSplatT * Math.max(6, paxH * 0.22),
      w: paxW,
      h: paxH,
    };
  }

  if (echo.kind === "board") {
    const bi = echo.transferIndex;
    const prog = smoothstep01(echo.progress);
    const staticOn = echo.staticOnboardCountAtDeath;
    const boardingLen = echo.boardingCountAtDeath;
    const totalInCab = staticOn + boardingLen;
    const slotIdx = staticOn + bi;
    const xStartRight = shaftLeft - queueMargin - bi * (paxW + queueGap);
    const xStartLeft = xStartRight - paxW;
    const xEndCenter = cabSlotCenterX(cabLeft, cabW, slotIdx, Math.max(1, totalInCab));
    const xEndLeft = xEndCenter - paxW / 2;
    const yStartTop = yFeetDock - paxH;
    const yEndTop = cy + cabH / 2 - paxH;
    const xLeft = xStartLeft + (xEndLeft - xStartLeft) * prog;
    const yTop = yStartTop + (yEndTop - yStartTop) * prog;
    return { xLeft, yTop, w: paxW, h: paxH };
  }

  const progress = echo.progress;
  const slotIdx = echo.transferIndex;
  const totalOnboard = echo.totalOnboardAtDeath;
  const xCabCenter = cabSlotCenterX(
    cabLeft,
    cabW,
    slotIdx,
    Math.max(1, totalOnboard),
  );
  const xCabLeft = xCabCenter - paxW / 2;
  const yCabTop = cy + cabH / 2 - paxH;
  const xLobbyLeft = shaftLeft - queueMargin - paxW;
  const yLobbyTop = yFeetDock - paxH;
  const split = DEBOARD_LOBBY_SEGMENT_FRAC;
  let xLeft: number;
  let yTop: number;
  if (progress < split) {
    const u = smoothstep01(progress / split);
    xLeft = xCabLeft + (xLobbyLeft - xCabLeft) * u;
    yTop = yCabTop + (yLobbyTop - yCabTop) * u;
  } else {
    const u = smoothstep01((progress - split) / (1 - split));
    const xExit = -paxW - 32;
    xLeft = xLobbyLeft + (xExit - xLobbyLeft) * u;
    yTop = yLobbyTop;
  }
  return { xLeft, yTop, w: paxW, h: paxH };
}

export function chipStyleForArchetype(archetype: Passenger["archetype"]): {
  fill: string;
  stroke: string;
  text: string;
} {
  return {
    fill: PASSENGER_BODY_FILL[archetype] ?? PASSENGER_BODY_FILL.regular,
    stroke: PASSENGER_BODY_STROKE,
    text: "#0f172a",
  };
}

const EMOJI_HEAD_FONT = 'system-ui, "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", sans-serif';
/** Base head size at unit scale; heavy still gets ×1.2 on this. */
const HEAD_EMOJI_BASE_PX = 40;
const DEBUG_HEAD_OVERLAY =
  typeof globalThis === "object" &&
  "location" in globalThis &&
  typeof globalThis.location?.search === "string" &&
  new URLSearchParams(globalThis.location.search).get("debugHeads") === "1";
const EMOJI_RASTER_PAD_FRAC = 0.75;
const EMOJI_RASTER_BUCKET_PX = 2;
const EMOJI_RASTER_CACHE_MAX = 48;
const EMOJI_RASTER_CACHE = new Map<string, EmojiRaster>();

type TextMetricBounds = Partial<
  Pick<
    TextMetrics,
    | "actualBoundingBoxAscent"
    | "actualBoundingBoxDescent"
  >
>;

type EmojiRaster = {
  canvas: HTMLCanvasElement;
  drawX: number;
  drawY: number;
  drawW: number;
  drawH: number;
};

export function quantizeEmojiRasterHeadPx(headPx: number): number {
  return Math.max(
    1,
    Math.round(headPx / EMOJI_RASTER_BUCKET_PX) * EMOJI_RASTER_BUCKET_PX,
  );
}

export function getBoundedCacheEntry<T>(
  cache: Map<string, T>,
  key: string,
): T | undefined {
  const cached = cache.get(key);
  if (cached === undefined) {
    return undefined;
  }
  cache.delete(key);
  cache.set(key, cached);
  return cached;
}

export function setBoundedCacheEntry<T>(
  cache: Map<string, T>,
  key: string,
  value: T,
  maxEntries: number,
): void {
  if (cache.has(key)) {
    cache.delete(key);
  }
  cache.set(key, value);
  while (cache.size > maxEntries) {
    const oldestKey = cache.keys().next().value;
    if (oldestKey === undefined) {
      break;
    }
    cache.delete(oldestKey);
  }
}

export function computeHeadEmojiPx(
  cameraLabelScale: number,
  paxW: number,
  paxH: number,
  archetype: Passenger["archetype"],
  dead: boolean,
): number {
  const s = cameraLabelScale;
  const base = HEAD_EMOJI_BASE_PX * s;
  const raw = !dead && archetype === "heavy" ? base * 1.2 : base;
  // Keep the head proportional to the body across viewports.
  // The key constraint is pax width on narrow screens (phone); cap there first.
  const capW = paxW * 0.9;
  const capH = paxH * 0.55;
  const minPx = 14 * s;
  return Math.max(minPx, Math.min(raw, capW, capH));
}

export function centeredTextBoundsOffset(metrics: TextMetricBounds): {
  y: number;
} {
  const ascent = metrics.actualBoundingBoxAscent;
  const descent = metrics.actualBoundingBoxDescent;
  return {
    y:
      ascent === undefined || descent === undefined
        ? 0
        : (ascent - descent) / 2,
  };
}

function scanNonTransparentBounds(
  data: Uint8ClampedArray,
  width: number,
  height: number,
): { left: number; top: number; right: number; bottom: number } | null {
  let left = width;
  let top = height;
  let right = -1;
  let bottom = -1;
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      const alpha = data[(y * width + x) * 4 + 3] ?? 0;
      if (alpha === 0) {
        continue;
      }
      if (x < left) {
        left = x;
      }
      if (x > right) {
        right = x;
      }
      if (y < top) {
        top = y;
      }
      if (y > bottom) {
        bottom = y;
      }
    }
  }
  return right >= left && bottom >= top
    ? { left, top, right, bottom }
    : null;
}

function rasterizeEmoji(glyph: string, headPx: number): EmojiRaster | null {
  if (typeof document === "undefined") {
    return null;
  }
  const quantizedHeadPx = quantizeEmojiRasterHeadPx(headPx);
  const cacheKey = `${glyph}@${quantizedHeadPx}`;
  const cached = getBoundedCacheEntry(EMOJI_RASTER_CACHE, cacheKey);
  if (cached) {
    return cached;
  }
  const pad = Math.max(8, Math.ceil(quantizedHeadPx * EMOJI_RASTER_PAD_FRAC));
  const size = Math.max(32, Math.ceil(quantizedHeadPx + pad * 2));
  const canvas = document.createElement("canvas");
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext("2d", { willReadFrequently: true });
  if (!ctx) {
    return null;
  }
  ctx.clearRect(0, 0, size, size);
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = `${quantizedHeadPx}px ${EMOJI_HEAD_FONT}`;
  ctx.fillText(glyph, size / 2, size / 2);
  const image = ctx.getImageData(0, 0, size, size);
  const bounds = scanNonTransparentBounds(image.data, size, size);
  if (!bounds) {
    return null;
  }
  const drawW = bounds.right - bounds.left + 1;
  const drawH = bounds.bottom - bounds.top + 1;
  const raster = {
    canvas,
    drawX: bounds.left,
    drawY: bounds.top,
    drawW,
    drawH,
  };
  setBoundedCacheEntry(
    EMOJI_RASTER_CACHE,
    cacheKey,
    raster,
    EMOJI_RASTER_CACHE_MAX,
  );
  return raster;
}

export function drawPassengerSilhouette(
  ctx: CanvasRenderingContext2D,
  xLeft: number,
  yTop: number,
  paxW: number,
  paxH: number,
  p: Passenger,
  opts: {
    destBadge?: boolean;
    danger?: boolean;
    cameraLabelScale?: number;
    nowMs?: number;
    /** Default true (faces right, moving +x in canvas). */
    facingRight?: boolean;
    /** In-cab with doors closed only: fast-ride fearful face. Omit when docked (open doors) or off-cab. */
    elevatorSpeed?: number;
  },
): void {
  const s = opts.cameraLabelScale ?? 1;
  const corner = Math.min(8, paxW * 0.22);
  if (opts.danger) {
    ctx.fillStyle = "rgba(185, 28, 28, 0.92)";
  } else {
    ctx.fillStyle = PASSENGER_BODY_FILL[p.archetype] ?? PASSENGER_BODY_FILL.regular;
  }
  ctx.beginPath();
  ctx.roundRect(xLeft, yTop, paxW, paxH, corner);
  ctx.fill();
  ctx.strokeStyle = PASSENGER_BODY_STROKE;
  ctx.lineWidth = 2.5;
  ctx.stroke();

  if (opts.destBadge) {
    const destNum = String(p.targetFloorIndex + 1);
    const destFontPx = Math.min(20 * s, paxH * 0.42, paxW * 0.55);
    const cx = xLeft + paxW / 2;
    const cy = yTop + paxH / 2;
    ctx.save();
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.font = `700 ${destFontPx}px system-ui, sans-serif`;
    ctx.shadowColor = "rgba(15, 23, 42, 0.9)";
    ctx.shadowBlur = 3 * s;
    ctx.fillStyle = "#f8fafc";
    ctx.fillText(destNum, cx, cy);
    ctx.shadowBlur = 0;
    ctx.restore();

    const dead = Boolean(opts.danger);
    const facingRight = opts.facingRight !== false;
    const nowMs = opts.nowMs;
    const headPx = computeHeadEmojiPx(s, paxW, paxH, p.archetype, dead);
    const headY = yTop;
    const glyph = passengerHeadSymbol(
      p.archetype,
      dead,
      opts.elevatorSpeed,
    );
    const urgentWiggle = !dead && p.archetype === "urgent" && nowMs !== undefined;

    ctx.save();
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.font = `${headPx}px ${EMOJI_HEAD_FONT}`;
    const metrics = ctx.measureText(glyph);
    const offset = centeredTextBoundsOffset(metrics);
    ctx.translate(cx, headY);
    if (!facingRight) {
      ctx.scale(-1, 1);
    }
    if (urgentWiggle) {
      ctx.rotate(
        0.1 * Math.sin((nowMs / 1000) * 2 * Math.PI),
      );
    }
    const raster = rasterizeEmoji(glyph, headPx);
    if (raster) {
      const destX = -raster.drawW / 2;
      const destY = offset.y - raster.drawH / 2;
      ctx.drawImage(
        raster.canvas,
        raster.drawX,
        raster.drawY,
        raster.drawW,
        raster.drawH,
        destX,
        destY,
        raster.drawW,
        raster.drawH,
      );
    } else {
      ctx.fillText(glyph, 0, offset.y);
    }
    if (DEBUG_HEAD_OVERLAY) {
      const bboxLeft = metrics.actualBoundingBoxLeft ?? 0;
      const bboxRight = metrics.actualBoundingBoxRight ?? 0;
      const bboxAscent = metrics.actualBoundingBoxAscent ?? 0;
      const bboxDescent = metrics.actualBoundingBoxDescent ?? 0;
      const boxX = -bboxLeft;
      const boxY = offset.y - bboxAscent;
      const boxW = bboxLeft + bboxRight;
      const boxH = bboxAscent + bboxDescent;

      ctx.strokeStyle = "rgba(255, 59, 48, 0.95)";
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(-6, 0);
      ctx.lineTo(6, 0);
      ctx.moveTo(0, -6);
      ctx.lineTo(0, 6);
      ctx.stroke();

      ctx.strokeStyle = "rgba(56, 189, 248, 0.95)";
      ctx.strokeRect(-paxW / 2, 0, paxW, paxH);

      if (boxW > 0 && boxH > 0) {
        ctx.strokeStyle = "rgba(250, 204, 21, 0.95)";
        ctx.strokeRect(boxX, boxY, boxW, boxH);
      }
    }
    ctx.restore();
  }
}
