/**
 * Tunable arcade physics (PRD §4.1). Edit values here to tune feel.
 */
export type PhysicsConfig = {
  /**
   * Base downward acceleration when thrust is off (sim units / s²).
   * Higher = less hang time / faster falls. Pairs with `minGravityFactor` + level blend altitudes.
   */
  gravity: number;
  /** Elevator mass with no passengers (kg, arbitrary scale). */
  baseMass: number;
  /**
   * Engine thrust (same arbitrary scale as gravity × mass).
   * Higher = stronger burn; if falls still feel floaty, raise `gravity` / `minGravityFactor` first, then tune thrust.
   */
  thrustForce: number;
  /** World altitude limits (sim units). */
  worldMinAltitude: number;
  /** Level vertical extent for camera span / gravity blend (not a motion ceiling). */
  levelMaxAltitude: number;
  /**
   * At a level’s `gravityBlendEndAltitude`, effective gravity ≈ `gravity * minGravityFactor`.
   * Closer to 1 = less “moon” (weaker reduction at altitude). ~0.45 feels very floaty; try 0.75–0.95.
   */
  minGravityFactor: number;
  /**
   * Linear air drag (1/s); 0 = none. Small values (e.g. 0.2–0.8) shave apex hang / coasting.
   */
  linearDrag: number;
  /** Fixed simulation step in seconds. */
  fixedTimestepSeconds: number;
  /** Max physics substeps per frame (spiral-of-death cap). */
  maxStepsPerFrame: number;
  /**
   * Death if a ground collision’s downward impact speed (sim / s) exceeds this.
   * Tuned for arcade; upward-only thrust cuts stay below this without a hard landing.
   */
  maxSafeGroundImpactSpeed: number;
};

export const defaultPhysicsConfig: PhysicsConfig = {
  gravity: 28,
  baseMass: 0.85,
  thrustForce: 80,
  worldMinAltitude: 0,
  levelMaxAltitude: 880, // align with Arc 1 L1 `extentMaxAltitude` (`src/config/arc1/level1.ts`) for defaults
  minGravityFactor: 0.82,
  linearDrag: 0.35,
  fixedTimestepSeconds: 1 / 120,
  maxStepsPerFrame: 8,
  maxSafeGroundImpactSpeed: 22,
};
