import { TRANSFER_DEATH_ECHO_SECONDS } from "../config/transferTiming.js";
import type { PhysicsConfig } from "../config/physics.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";
import type { GameSimState, TransferDeathEcho, UrgentWaitWalkoff } from "./gameState.js";
import { stepElevator, type GroundImpact } from "./elevator.js";
import { findDockableFloorIndex } from "./docking.js";
import type { Passenger, Transfer } from "./passenger.js";
import { totalElevatorMass } from "./passenger.js";
import { clampRunScore } from "./scoreAttack.js";
import { stepFloorInteraction } from "./floorInteraction.js";
import { trySpawnOneWaitingPassenger } from "./spawnPassengers.js";

function stepTransferDeathEchoes(state: GameSimState, dt: number): GameSimState {
  if (state.transferDeathEchoes.length === 0) {
    return state;
  }
  const transferDeathEchoes = state.transferDeathEchoes
    .map((e) => ({ ...e, remainingSec: e.remainingSec - dt }))
    .filter((e) => e.remainingSec > 0);
  return { ...state, transferDeathEchoes };
}

function buildGroundImpactKills(
  state: GameSimState,
  level: LevelGameConfig,
): {
  victims: Passenger[];
  deboarding: readonly Transfer[];
  boarding: readonly Transfer[];
  floorIndex: number;
} {
  const floorIndex =
    state.floor.tag === "doorsOpen"
      ? state.floor.floorIndex
      : (findDockableFloorIndex(
          state.elevator.altitude,
          state.elevator.velocity,
          level,
        ) ?? 0);
  const deboarding =
    state.floor.tag === "doorsOpen" ? state.floor.deboarding : [];
  const boarding = state.floor.tag === "doorsOpen" ? state.floor.boarding : [];
  const byId = new Map<number, Passenger>();
  for (const p of state.onboard) {
    byId.set(p.id, p);
  }
  for (const t of boarding) {
    byId.set(t.passenger.id, t.passenger);
  }
  return {
    victims: [...byId.values()],
    deboarding,
    boarding,
    floorIndex,
  };
}

/**
 * Lethal splat: everyone in the cab or crossing the doors dies; same 0.5*scoreValue penalty
 * pattern as hover-break transfer kills, plus transfer death echoes when applicable.
 */
function applyLethalGroundImpact(
  state: GameSimState,
  physics: PhysicsConfig,
  level: LevelGameConfig,
  impact: GroundImpact,
): { state: GameSimState; lethalApplied: boolean } {
  if (!impact.hitGround) {
    return { state, lethalApplied: false };
  }
  if (impact.impactSpeedDown <= physics.maxSafeGroundImpactSpeed) {
    return { state, lethalApplied: false };
  }
  const { victims, deboarding, boarding, floorIndex } = buildGroundImpactKills(
    state,
    level,
  );
  if (victims.length === 0) {
    return { state, lethalApplied: false };
  }
  const penalizedIds = new Set<number>();
  let killPenalty = 0;
  for (const p of victims) {
    if (penalizedIds.has(p.id)) {
      continue;
    }
    penalizedIds.add(p.id);
    killPenalty += 0.5 * p.scoreValue;
  }
  const staticOnboardCountAtDeath = state.onboard.filter(
    (p) => !deboarding.some((t) => t.passenger.id === p.id),
  ).length;
  const totalOnboardAtDeath = state.onboard.length;
  const boardingCountAtDeath = boarding.length;
  const dur = TRANSFER_DEATH_ECHO_SECONDS;
  const newEchoes: TransferDeathEcho[] = [];
  for (let di = 0; di < deboarding.length; di += 1) {
    const t = deboarding[di]!;
    const slotIdx = state.onboard.findIndex((p) => p.id === t.passenger.id);
    newEchoes.push({
      remainingSec: dur,
      passenger: t.passenger,
      floorIndex,
      kind: "deboard",
      progress: t.progress,
      transferIndex: slotIdx >= 0 ? slotIdx : di,
      staticOnboardCountAtDeath,
      boardingCountAtDeath,
      totalOnboardAtDeath,
    });
  }
  for (let bi = 0; bi < boarding.length; bi += 1) {
    const t = boarding[bi]!;
    newEchoes.push({
      remainingSec: dur,
      passenger: t.passenger,
      floorIndex,
      kind: "board",
      progress: t.progress,
      transferIndex: bi,
      staticOnboardCountAtDeath,
      boardingCountAtDeath,
      totalOnboardAtDeath,
    });
  }
  const deboardIdSet = new Set(
    deboarding.map((t) => t.passenger.id),
  );
  for (let i = 0; i < state.onboard.length; i += 1) {
    const p = state.onboard[i]!;
    if (deboardIdSet.has(p.id)) {
      continue;
    }
    newEchoes.push({
      remainingSec: dur,
      passenger: p,
      floorIndex,
      kind: "ground",
      progress: 1,
      transferIndex: i,
      staticOnboardCountAtDeath,
      boardingCountAtDeath,
      totalOnboardAtDeath: state.onboard.length,
    });
  }
  return {
    state: {
      ...state,
      onboard: [],
      floor: { tag: "idle", hoverFloor: null, stableHoverSec: 0 },
      runScore: clampRunScore(state.runScore - killPenalty),
      transferDeathEchoes: [...state.transferDeathEchoes, ...newEchoes],
      elevator: { ...state.elevator, mass: physics.baseMass },
    },
    lethalApplied: true,
  };
}

function stepUrgentWaitWalkoffs(state: GameSimState, dt: number): GameSimState {
  if (state.urgentWaitWalkoffs.length === 0) {
    return state;
  }
  const urgentWaitWalkoffs: UrgentWaitWalkoff[] = [];
  for (const w of state.urgentWaitWalkoffs) {
    const prog = w.progress + dt / w.durationSeconds;
    if (prog < 1) {
      urgentWaitWalkoffs.push({ ...w, progress: prog });
    }
  }
  return { ...state, urgentWaitWalkoffs };
}

export type StepGameResult = {
  state: GameSimState;
  /**
   * True if this substep applied lethal ground impact (cab cleared, score penalty, echoes).
   * The app may end the run when this is set and `level.groundCrashEndsRun` is true.
   */
  lethalGroundImpact: boolean;
};

/**
 * One fixed timestep: elevator physics (with current mass), then floor hover / transfers.
 */
export function stepGame(
  state: GameSimState,
  thrustActive: boolean,
  physics: PhysicsConfig,
  level: LevelGameConfig,
  gravityEffective: number,
  dt: number,
): StepGameResult {
  const mass = totalElevatorMass(physics.baseMass, state.onboard);
  const el0 = { ...state.elevator, mass };
  const { state: eNext, impact } = stepElevator(
    el0,
    thrustActive,
    physics,
    dt,
    gravityEffective,
  );
  let next: GameSimState = { ...state, elevator: eNext };
  const { state: afterLethal, lethalApplied } = applyLethalGroundImpact(
    next,
    physics,
    level,
    impact,
  );
  next = afterLethal;
  next = stepFloorInteraction(next, level, physics.baseMass, dt);
  next = stepUrgentWaitWalkoffs(next, dt);
  next = stepTransferDeathEchoes(next, dt);
  next = stepPassengerSpawn(next, level, dt);
  const mass2 = totalElevatorMass(physics.baseMass, next.onboard);
  return {
    state: {
      ...next,
      elevator: { ...next.elevator, mass: mass2 },
      runScore: clampRunScore(next.runScore),
    },
    lethalGroundImpact: lethalApplied,
  };
}

function stepPassengerSpawn(
  state: GameSimState,
  level: LevelGameConfig,
  dt: number,
): GameSimState {
  const interval = level.passengerSpawnIntervalSeconds;
  if (interval <= 0) {
    return state;
  }
  let acc = state.spawnAccumSec + dt;
  let waitingByFloor = state.waitingByFloor;
  let nextPassengerId = state.nextPassengerId;
  let spawnRngState = state.spawnRngState;

  while (acc >= interval) {
    acc -= interval;
    const r = trySpawnOneWaitingPassenger(
      waitingByFloor,
      {
        floorAltitudes: level.floorAltitudes,
        allowedPassengerTypes: level.allowedPassengerTypes,
        maxWaitingPerFloor: level.maxWaitingPerFloor,
        disallowedSourceFloorIndices:
          level.teachBlockGroundSpawnsAfterFirstBoardUntilNonGroundDock ===
            true && state.teachBlockGroundSpawns
            ? [0]
            : undefined,
      },
      spawnRngState,
      nextPassengerId,
    );
    waitingByFloor = r.waitingByFloor;
    spawnRngState = r.rngState;
    nextPassengerId = r.nextId;
    if (!r.spawned) {
      break;
    }
  }

  return {
    ...state,
    waitingByFloor,
    nextPassengerId,
    spawnRngState,
    spawnAccumSec: acc,
  };
}
