/** Host-only: score attack timer and fixed-step sim run only in this state. */
export type RunPhase = "menu" | "doorOpen" | "play" | "paused";

export type AppScreen = "menu" | "playing" | "levelComplete" | "gameOver";

/**
 * Thrust, fixed-step sim, and score-attack timer should advance only when the player
 * is in normal play. The main-menu door intro (`doorOpen`) and user pause (`paused`)
 * keep sim and timer frozen.
 */
export function shouldRunHostGameplay(
  appScreen: AppScreen,
  runPhase: RunPhase,
): boolean {
  return appScreen === "playing" && runPhase === "play";
}

export function shouldTickTimer(
  appScreen: AppScreen,
  runPhase: RunPhase,
): boolean {
  return shouldRunHostGameplay(appScreen, runPhase);
}
