import type { LevelGameConfig } from "../../config/levelGameConfig.js";
import { CAB_GLASS_FILL_ALPHA, PAX_HEIGHT_FRAC_OF_CAB } from "../../config/passengerVisual.js";
import { TRANSFER_DEATH_ECHO_SECONDS } from "../../config/transferTiming.js";
import { floorHoverBandAltitudes } from "../../sim/docking.js";
import type { GameSimState } from "../../sim/gameState.js";
import { URGENT_PATIENCE_SECONDS } from "../../sim/passenger.js";
import {
  worldAltitudeToCanvasY,
  worldAltitudeDeltaToCanvasPx,
} from "./canvasSpace.js";
import {
  drawUrgencyBarAbovePassenger,
  computeHeadEmojiPx,
  paxSizeForCab,
  cabSlotCenterX,
  transferPassengerLayout,
  urgentWaitWalkoffLayout,
  drawPassengerSilhouette,
  type TransferLayoutGeom,
} from "./passengerLayer.js";
import type { RenderContext } from "./types.js";

export function drawFrame(
  rc: RenderContext,
  game: GameSimState,
  level: LevelGameConfig,
  cameraCenterAltitude: number,
  nowMs: number,
): void {
  const state = game.elevator;
  const { canvas, ctx, dpr } = rc;
  const cssH = canvas.clientHeight;
  const cssW = canvas.clientWidth;
  const vh = level.viewHalfSim;
  const designHalf = level.viewHalfSimBase ?? level.viewHalfSim;
  const cameraUiScale = designHalf / Math.max(1e-6, vh);

  ctx.save();
  ctx.scale(dpr, dpr);

  const shaftPadPx = 6;
  const cabH = Math.max(
    16,
    worldAltitudeDeltaToCanvasPx(level.elevatorCabHeightSim, vh, cssH),
  );
  const simWOverH =
    level.elevatorCabWidthSim / Math.max(0.001, level.elevatorCabHeightSim);
  const cabW = Math.max(16, cabH * simWOverH);
  const shaftW = cabW + 2 * shaftPadPx;
  const midX = cssW / 2;
  const shaftLeft = midX - shaftW / 2;
  const shaftRight = midX + shaftW / 2;
  const shaftCx = midX;

  ctx.fillStyle = "#0d1117";
  ctx.fillRect(0, 0, cssW, cssH);

  const gridColor = "#1f2937";
  ctx.strokeStyle = gridColor;
  ctx.lineWidth = 2;
  const stepPx = 48;
  for (let x = 0; x < shaftLeft; x += stepPx) {
    ctx.beginPath();
    ctx.moveTo(x + 0.5, 0);
    ctx.lineTo(x + 0.5, cssH);
    ctx.stroke();
  }
  for (let x = shaftRight; x < cssW; x += stepPx) {
    ctx.beginPath();
    ctx.moveTo(x + 0.5, 0);
    ctx.lineTo(x + 0.5, cssH);
    ctx.stroke();
  }
  for (let y = 0; y < cssH; y += stepPx) {
    ctx.beginPath();
    ctx.moveTo(0, y + 0.5);
    ctx.lineTo(shaftLeft, y + 0.5);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(shaftRight, y + 0.5);
    ctx.lineTo(cssW, y + 0.5);
    ctx.stroke();
  }

  ctx.fillStyle = "#070a0f";
  ctx.fillRect(shaftLeft, 0, shaftW, cssH);

  const railColor = "#1e293b";
  ctx.strokeStyle = railColor;
  ctx.lineWidth = 6;
  ctx.beginPath();
  ctx.moveTo(shaftLeft + 3, 0);
  ctx.lineTo(shaftLeft + 3, cssH);
  ctx.moveTo(shaftRight - 3, 0);
  ctx.lineTo(shaftRight - 3, cssH);
  ctx.stroke();

  for (let fi = 0; fi < level.floorAltitudes.length; fi += 1) {
    const band = floorHoverBandAltitudes(fi, level);
    if (!band) {
      continue;
    }
    const yHigh = worldAltitudeToCanvasY(
      band.high,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yLow = worldAltitudeToCanvasY(
      band.low,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yTopBand = Math.min(yHigh, yLow);
    const hBand = Math.max(1, Math.abs(yLow - yHigh));
    ctx.fillStyle = "rgba(168, 85, 247, 0.22)";
    ctx.fillRect(shaftLeft, yTopBand, shaftW, hBand);
    ctx.strokeStyle = "rgba(192, 132, 252, 0.55)";
    ctx.lineWidth = 2;
    ctx.strokeRect(shaftLeft + 0.5, yTopBand + 0.5, shaftW - 1, hBand - 1);
  }

  const floorSlabSim = level.floorSlabSim;
  const lobbyHeightSim = level.lobbyHeightSim;
  const floorDoorJambPx = 10;

  for (let fi = 0; fi < level.floorAltitudes.length; fi += 1) {
    const fa = level.floorAltitudes[fi]!;
    const slabTopAlt = fa + floorSlabSim;
    const lobbyTopAlt = slabTopAlt + lobbyHeightSim;

    const yLobbyTop = worldAltitudeToCanvasY(
      lobbyTopAlt,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const ySlabTop = worldAltitudeToCanvasY(
      slabTopAlt,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const ySlabBot = worldAltitudeToCanvasY(fa, cameraCenterAltitude, vh, cssH);

    ctx.fillStyle = "rgba(30, 41, 59, 0.92)";
    ctx.fillRect(0, yLobbyTop, shaftLeft, ySlabTop - yLobbyTop);

    ctx.fillStyle = "#334155";
    ctx.fillRect(0, ySlabTop, shaftLeft, ySlabBot - ySlabTop);

    const doorTop = Math.min(yLobbyTop, ySlabTop);
    const doorH = Math.max(1, Math.abs(ySlabTop - yLobbyTop));
    ctx.fillStyle = "#1e293b";
    ctx.fillRect(
      shaftLeft - floorDoorJambPx,
      doorTop,
      floorDoorJambPx,
      doorH,
    );
    ctx.strokeStyle = "#64748b";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(shaftLeft + 0.5, doorTop);
    ctx.lineTo(shaftLeft + 0.5, doorTop + doorH);
    ctx.stroke();
    ctx.strokeStyle = "#94a3b8";
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(0, ySlabBot + 0.5);
    ctx.lineTo(shaftLeft, ySlabBot + 0.5);
    ctx.stroke();

    const floorLabel = String(fi + 1);
    const yMid = (yLobbyTop + ySlabTop) / 2;
    const floorLabelPadX = 12 * cameraUiScale;
    ctx.font = `600 ${30 * cameraUiScale}px system-ui, sans-serif`;
    ctx.fillStyle = "#e2e8f0";
    ctx.textAlign = "left";
    ctx.textBaseline = "middle";
    ctx.fillText(floorLabel, floorLabelPadX, yMid);
  }

  const failY = worldAltitudeToCanvasY(
    level.failureAltitude,
    cameraCenterAltitude,
    vh,
    cssH,
  );
  ctx.strokeStyle = "rgba(239, 68, 68, 0.85)";
  ctx.lineWidth = 4;
  ctx.setLineDash([20, 16]);
  ctx.beginPath();
  ctx.moveTo(0, failY + 0.5);
  ctx.lineTo(cssW, failY + 0.5);
  ctx.stroke();
  ctx.setLineDash([]);

  ctx.fillStyle = "rgba(248, 113, 113, 0.12)";
  ctx.fillRect(0, 0, cssW, Math.max(0, failY));

  ctx.strokeStyle = "#475569";
  ctx.lineWidth = 4;
  ctx.strokeRect(shaftLeft + 0.5, 0.5, shaftW - 1, cssH - 1);

  const cy = worldAltitudeToCanvasY(
    state.altitude,
    cameraCenterAltitude,
    vh,
    cssH,
  );
  const cabLeft = shaftCx - cabW / 2;
  const cabTop = cy - cabH / 2;

  const barW = Math.min(cssW - 32, cabW + 32);
  const barLeft = shaftCx - barW / 2;
  const barH = 10;
  const dockBarTop = cabTop - barH - 12;

  let dockBarLabel: string | null = null;
  const idleDockingCountdown =
    game.floor.tag === "idle" &&
    game.floor.hoverFloor !== null &&
    game.floor.stableHoverSec > 0;
  const showDockBar =
    game.floor.tag === "doorsOpen" || idleDockingCountdown;

  if (showDockBar) {
    ctx.fillStyle = "rgba(30, 41, 59, 0.95)";
    ctx.strokeStyle = "rgba(71, 85, 105, 0.9)";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.roundRect(barLeft, dockBarTop, barW, barH, 6);
    ctx.fill();
    ctx.stroke();

    if (game.floor.tag === "doorsOpen") {
      const transfers = [...game.floor.deboarding, ...game.floor.boarding];
      if (transfers.length > 0) {
        let sum = 0;
        for (const t of transfers) {
          sum += t.progress;
        }
        const boardFrac = sum / transfers.length;
        ctx.fillStyle = "rgba(251, 191, 36, 0.92)";
        ctx.beginPath();
        ctx.roundRect(barLeft + 2, dockBarTop + 2, (barW - 4) * boardFrac, barH - 4, 4);
        ctx.fill();
      }

      if (game.floor.deboarding.length > 0) {
        dockBarLabel = "Deboarding";
      } else if (game.floor.boarding.length > 0) {
        dockBarLabel = "Boarding";
      }
    } else {
      const dockFrac = Math.min(
        1,
        game.floor.stableHoverSec / level.stableHoverSeconds,
      );
      if (dockFrac > 0) {
        ctx.fillStyle = "rgba(56, 189, 248, 0.92)";
        ctx.beginPath();
        ctx.roundRect(
          barLeft + 2,
          dockBarTop + 2,
          (barW - 4) * dockFrac,
          barH - 4,
          4,
        );
        ctx.fill();
      }
      dockBarLabel = "Docking";
    }
  }

  if (dockBarLabel !== null) {
    ctx.font = "600 22px system-ui, sans-serif";
    ctx.fillStyle = "#cbd5e1";
    ctx.textAlign = "center";
    ctx.textBaseline = "bottom";
    ctx.fillText(dockBarLabel, barLeft + barW / 2, dockBarTop - 8);
  }

  const queueGap = Math.max(6, Math.round(cabW * 0.045));
  const queueMargin = Math.max(12, Math.round(cabW * 0.06));

  const boardingIds =
    game.floor.tag === "doorsOpen"
      ? new Set(game.floor.boarding.map((t) => t.passenger.id))
      : new Set<number>();

  const cabPaxHCap = Math.min(cabH * PAX_HEIGHT_FRAC_OF_CAB * 1.08, cabH * 0.88);

  if (game.floor.tag === "doorsOpen") {
    const fiOpen = game.floor.floorIndex;
    const faOpen = level.floorAltitudes[fiOpen]!;
    const slabTopOpen = faOpen + floorSlabSim;
    const yFeetDock = worldAltitudeToCanvasY(
      slabTopOpen,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yLobbyTopDock = worldAltitudeToCanvasY(
      slabTopOpen + lobbyHeightSim,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const maxPaxHDock = Math.max(20, Math.abs(yFeetDock - yLobbyTopDock) * 0.92);

    const { deboarding, boarding } = game.floor;
    const deboardingIds = new Set(deboarding.map((t) => t.passenger.id));
    const staticOnboard = game.onboard.filter((p) => !deboardingIds.has(p.id));

    const layoutGeom: TransferLayoutGeom = {
      cabW,
      cabH,
      cabLeft,
      cy,
      shaftLeft,
      queueMargin,
      queueGap,
      yFeetDock,
      maxPaxHDock,
    };

    for (let bi = 0; bi < boarding.length; bi += 1) {
      const tr = boarding[bi]!;
      const box = transferPassengerLayout(layoutGeom, {
        kind: "board",
        passenger: tr.passenger,
        progress: tr.progress,
        transferIndex: bi,
        staticOnboardCountAtDeath: staticOnboard.length,
        boardingCountAtDeath: boarding.length,
        totalOnboardAtDeath: game.onboard.length,
      });
      drawPassengerSilhouette(ctx, box.xLeft, box.yTop, box.w, box.h, tr.passenger, {
        destBadge: true,
        cameraLabelScale: cameraUiScale,
        nowMs,
        facingRight: true,
      });
    }

    for (let di = 0; di < deboarding.length; di += 1) {
      const tr = deboarding[di]!;
      const p = tr.passenger;
      const slotIdxAll = game.onboard.findIndex((x) => x.id === p.id);
      const slotIdx = slotIdxAll >= 0 ? slotIdxAll : di;
      const box = transferPassengerLayout(layoutGeom, {
        kind: "deboard",
        passenger: p,
        progress: tr.progress,
        transferIndex: slotIdx,
        staticOnboardCountAtDeath: staticOnboard.length,
        boardingCountAtDeath: boarding.length,
        totalOnboardAtDeath: game.onboard.length,
      });
      drawPassengerSilhouette(ctx, box.xLeft, box.yTop, box.w, box.h, p, {
        destBadge: true,
        cameraLabelScale: cameraUiScale,
        nowMs,
        facingRight: false,
      });
    }

    const staticCount = staticOnboard.length;
    for (let si = 0; si < staticOnboard.length; si += 1) {
      const p = staticOnboard[si]!;
      const { w: paxW, h: paxH } = paxSizeForCab(cabW, cabH, p.archetype, cabPaxHCap);
      const cx = cabSlotCenterX(cabLeft, cabW, si, Math.max(1, staticCount));
      const xLeft = cx - paxW / 2;
      const yTop = cy + cabH / 2 - paxH;
      drawPassengerSilhouette(ctx, xLeft, yTop, paxW, paxH, p, {
        destBadge: true,
        cameraLabelScale: cameraUiScale,
        nowMs,
        facingRight: true,
      });
    }
  } else {
    const nOn = Math.max(1, game.onboard.length);
    for (let si = 0; si < game.onboard.length; si += 1) {
      const p = game.onboard[si]!;
      const { w: paxW, h: paxH } = paxSizeForCab(cabW, cabH, p.archetype, cabPaxHCap);
      const cx = cabSlotCenterX(cabLeft, cabW, si, nOn);
      const xLeft = cx - paxW / 2;
      const yTop = cy + cabH / 2 - paxH;
      drawPassengerSilhouette(ctx, xLeft, yTop, paxW, paxH, p, {
        destBadge: true,
        cameraLabelScale: cameraUiScale,
        nowMs,
        elevatorSpeed: state.velocity,
        facingRight: true,
      });
    }
  }

  for (let fi = 0; fi < level.floorAltitudes.length; fi += 1) {
    const fa = level.floorAltitudes[fi]!;
    const slabTopAlt = fa + floorSlabSim;
    const yFeet = worldAltitudeToCanvasY(
      slabTopAlt,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yLobbyTop = worldAltitudeToCanvasY(
      slabTopAlt + lobbyHeightSim,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const maxPaxHInLobby = Math.max(20, Math.abs(yFeet - yLobbyTop) * 0.92);
    const queue = game.waitingByFloor[fi] ?? [];
    for (let qi = 0; qi < queue.length; qi += 1) {
      const p = queue[qi]!;
      if (boardingIds.has(p.id)) {
        continue;
      }
      const { w: paxW, h: paxH } = paxSizeForCab(
        cabW,
        cabH,
        p.archetype,
        maxPaxHInLobby,
      );
      const xRight = shaftLeft - queueMargin - qi * (paxW + queueGap);
      const xLeft = xRight - paxW;
      const yTop = yFeet - paxH;
      if (
        p.archetype === "urgent" &&
        p.urgencyTimerSeconds !== undefined
      ) {
        const maxU =
          p.urgencyPatienceMaxSeconds ?? URGENT_PATIENCE_SECONDS;
        const headPx = computeHeadEmojiPx(cameraUiScale, paxW, paxH, p.archetype, false);
        const headRoom = 4 * cameraUiScale + headPx * 0.5;
        drawUrgencyBarAbovePassenger(
          ctx,
          xLeft,
          yTop,
          paxW,
          p.urgencyTimerSeconds,
          maxU,
          headRoom,
        );
      }
      drawPassengerSilhouette(ctx, xLeft, yTop, paxW, paxH, p, {
        destBadge: true,
        cameraLabelScale: cameraUiScale,
        nowMs,
        facingRight: true,
      });
    }
  }

  for (const wo of game.urgentWaitWalkoffs) {
    const faW = level.floorAltitudes[wo.floorIndex]!;
    const slabTopW = faW + floorSlabSim;
    const yFeetW = worldAltitudeToCanvasY(
      slabTopW,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yLobbyW = worldAltitudeToCanvasY(
      slabTopW + lobbyHeightSim,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const maxPaxHW = Math.max(20, Math.abs(yFeetW - yLobbyW) * 0.92);
    const box = urgentWaitWalkoffLayout(
      {
        cabW,
        cabH,
        shaftLeft,
        queueMargin,
        queueGap,
        yFeet: yFeetW,
        maxPaxHInLobby: maxPaxHW,
      },
      wo,
    );
    ctx.save();
    ctx.globalAlpha = 1 - 0.22 * wo.progress;
    drawPassengerSilhouette(ctx, box.xLeft, box.yTop, box.w, box.h, wo.passenger, {
      destBadge: true,
      cameraLabelScale: cameraUiScale,
      nowMs,
      facingRight: false,
    });
    ctx.restore();
  }

  const r = Math.min(16, cabW * 0.12);
  const glassBase = state.thrustActive ? "249, 115, 22" : "100, 116, 139";
  const glassAlpha = state.thrustActive
    ? CAB_GLASS_FILL_ALPHA + 0.06
    : CAB_GLASS_FILL_ALPHA;
  ctx.fillStyle = `rgba(${glassBase}, ${glassAlpha})`;
  ctx.strokeStyle = "#e2e8f0";
  ctx.lineWidth = 4;
  ctx.beginPath();
  ctx.roundRect(cabLeft, cabTop, cabW, cabH, r);
  ctx.fill();
  ctx.stroke();

  if (state.thrustActive) {
    ctx.fillStyle = "rgba(251, 146, 60, 0.55)";
    ctx.beginPath();
    const flame = 72 + 16 * Math.sin(nowMs / 40);
    const flameHalf = Math.max(12, cabW * 0.2);
    ctx.moveTo(shaftCx - flameHalf, cy + cabH / 2);
    ctx.lineTo(shaftCx, cy + cabH / 2 + flame);
    ctx.lineTo(shaftCx + flameHalf, cy + cabH / 2);
    ctx.closePath();
    ctx.fill();
  }

  if (game.floor.tag === "doorsOpen") {
    const fa = level.floorAltitudes[game.floor.floorIndex]!;
    const slabTopOpen = fa + floorSlabSim;
    const yLobbyOpen = worldAltitudeToCanvasY(
      slabTopOpen + lobbyHeightSim,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const ySlabTopOpen = worldAltitudeToCanvasY(
      slabTopOpen,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const doorOpenTop = Math.min(yLobbyOpen, ySlabTopOpen);
    const doorOpenH = Math.max(1, Math.abs(ySlabTopOpen - yLobbyOpen));
    ctx.strokeStyle = "rgba(52, 211, 153, 0.75)";
    ctx.lineWidth = 6;
    ctx.strokeRect(shaftLeft - 4, doorOpenTop, shaftW + 8, doorOpenH);
  }

  for (const echo of game.transferDeathEchoes) {
    const faEcho = level.floorAltitudes[echo.floorIndex]!;
    const slabTopEcho = faEcho + floorSlabSim;
    const yFeetEcho = worldAltitudeToCanvasY(
      slabTopEcho,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const yLobbyEcho = worldAltitudeToCanvasY(
      slabTopEcho + lobbyHeightSim,
      cameraCenterAltitude,
      vh,
      cssH,
    );
    const maxPaxHEcho = Math.max(20, Math.abs(yFeetEcho - yLobbyEcho) * 0.92);
    const dur = TRANSFER_DEATH_ECHO_SECONDS;
    const fade = Math.min(1, echo.remainingSec / dur);
    const groundSplatT = echo.kind === "ground" ? 1 - fade : 0;
    const box = transferPassengerLayout(
      {
        cabW,
        cabH,
        cabLeft,
        cy,
        shaftLeft,
        queueMargin,
        queueGap,
        yFeetDock: yFeetEcho,
        maxPaxHDock: maxPaxHEcho,
      },
      echo,
      groundSplatT,
    );
    ctx.save();
    ctx.globalAlpha = 0.38 + 0.52 * fade;
    const echoDeadFacing = echo.kind !== "deboard";
    drawPassengerSilhouette(ctx, box.xLeft, box.yTop, box.w, box.h, echo.passenger, {
      destBadge: true,
      danger: true,
      cameraLabelScale: cameraUiScale,
      nowMs,
      facingRight: echoDeadFacing,
    });
    ctx.restore();
    const pad = Math.max(6, Math.min(box.w, box.h) * 0.12);
    ctx.strokeStyle = `rgba(254, 242, 242, ${0.45 + 0.45 * fade})`;
    ctx.lineWidth = 5;
    ctx.beginPath();
    ctx.moveTo(box.xLeft + pad, box.yTop + pad);
    ctx.lineTo(box.xLeft + box.w - pad, box.yTop + box.h - pad);
    ctx.moveTo(box.xLeft + box.w - pad, box.yTop + pad);
    ctx.lineTo(box.xLeft + pad, box.yTop + box.h - pad);
    ctx.stroke();
  }

  let echoFlashMax = 0;
  for (const e of game.transferDeathEchoes) {
    echoFlashMax = Math.max(echoFlashMax, e.remainingSec);
  }
  if (echoFlashMax > 0) {
    const u = Math.min(1, echoFlashMax / TRANSFER_DEATH_ECHO_SECONDS);
    const cxFlash = cssW / 2;
    const cyFlash = cssH / 2;
    const rad = Math.max(cssW, cssH) * 0.72;
    const g = ctx.createRadialGradient(cxFlash, cyFlash, 0, cxFlash, cyFlash, rad);
    g.addColorStop(0, `rgba(220, 38, 38, ${0.2 * u})`);
    g.addColorStop(0.55, `rgba(127, 29, 29, ${0.12 * u})`);
    g.addColorStop(1, "rgba(15, 23, 42, 0)");
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, cssW, cssH);
  }

  ctx.font = "12px system-ui, sans-serif";
  ctx.fillStyle = "#64748b";
  ctx.textAlign = "left";
  ctx.textBaseline = "alphabetic";
  const hud = `Speed ${state.velocity.toFixed(2)} · Accel ${state.acceleration.toFixed(2)}`;
  ctx.fillText(hud, 8, cssH - 10);
  if (game.floor.tag === "doorsOpen") {
    ctx.fillStyle = "#34d399";
    ctx.fillText("Doors open — transfer", 8, cssH - 26);
  }

  ctx.restore();
}
