import type { PassengerArchetypeMvp, Passenger } from "./passenger.js";
import { createPassenger } from "./passenger.js";

export type LevelSpawnConfig = {
  floorAltitudes: readonly number[];
  allowedPassengerTypes: readonly PassengerArchetypeMvp[];
  initialPassengerCount: number;
  maxWaitingPerFloor: number;
  /** See `LevelGameConfig.ensureWaitingOnFloorsAtStart`. */
  ensureWaitingOnFloorsAtStart?: readonly number[];
};

/** Deterministic PRNG (Mulberry32). */
export function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a += 0x6d2b79f5;
    let t = a;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * One step of Mulberry32; `state` is the internal `a` value (use seed for first call).
 * Matches successive calls to `mulberry32(seed)` when `state` is threaded between steps.
 */
export function mulberry32Step(state: number): { state: number; u: number } {
  let a = state >>> 0;
  a += 0x6d2b79f5;
  let t = a;
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  const u = ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  return { state: a, u };
}

function pickArchetype(
  allowed: readonly PassengerArchetypeMvp[],
  rng: () => number,
): PassengerArchetypeMvp {
  const i = Math.floor(rng() * allowed.length);
  return allowed[Math.min(i, allowed.length - 1)]!;
}

/**
 * First-pass spawn (PRD §9): uniform random source floor, uniform target ≠ source.
 * Buckets passengers into `waitingByFloor[sourceFloorIndex]` (capped per floor).
 */
export function spawnWaitingByFloor(
  cfg: LevelSpawnConfig,
  rng: () => number,
  startId: number,
): { waitingByFloor: Passenger[][]; nextId: number } {
  const nFloors = cfg.floorAltitudes.length;
  const waitingByFloor: Passenger[][] = Array.from({ length: nFloors }, () => []);
  const counts = new Int32Array(nFloors);
  let id = startId;

  for (let k = 0; k < cfg.initialPassengerCount; k += 1) {
    const sourceFloorIndex = Math.floor(rng() * nFloors);
    if (counts[sourceFloorIndex]! >= cfg.maxWaitingPerFloor) {
      continue;
    }
    let targetFloorIndex = Math.floor(rng() * nFloors);
    if (nFloors > 1) {
      while (targetFloorIndex === sourceFloorIndex) {
        targetFloorIndex = Math.floor(rng() * nFloors);
      }
    }
    const archetype = pickArchetype(cfg.allowedPassengerTypes, rng);
    const p: Passenger = createPassenger(
      id,
      sourceFloorIndex,
      targetFloorIndex,
      archetype,
    );
    id += 1;
    waitingByFloor[sourceFloorIndex]!.push(p);
    counts[sourceFloorIndex]! += 1;
  }

  for (const floorIndex of cfg.ensureWaitingOnFloorsAtStart ?? []) {
    if (floorIndex < 0 || floorIndex >= nFloors) {
      continue;
    }
    if (counts[floorIndex]! >= cfg.maxWaitingPerFloor) {
      continue;
    }
    if (waitingByFloor[floorIndex]!.length > 0) {
      continue;
    }
    if (nFloors < 2) {
      continue;
    }
    let targetFloorIndex = Math.floor(rng() * nFloors);
    let guard = 0;
    while (targetFloorIndex === floorIndex && guard < 32) {
      targetFloorIndex = Math.floor(rng() * nFloors);
      guard += 1;
    }
    if (targetFloorIndex === floorIndex) {
      continue;
    }
    const archetype = pickArchetype(cfg.allowedPassengerTypes, rng);
    const p: Passenger = createPassenger(
      id,
      floorIndex,
      targetFloorIndex,
      archetype,
    );
    id += 1;
    waitingByFloor[floorIndex]!.push(p);
    counts[floorIndex]! += 1;
  }

  return { waitingByFloor, nextId: id };
}

const SPAWN_ATTEMPTS_MAX = 24;

/**
 * If any floor queue is below `maxWaitingPerFloor`, spawn one passenger there.
 * Updates threaded Mulberry32 `rngState` for the next call.
 */
export function trySpawnOneWaitingPassenger(
  waitingByFloor: readonly Passenger[][],
  cfg: Pick<
    LevelSpawnConfig,
    "floorAltitudes" | "allowedPassengerTypes" | "maxWaitingPerFloor"
  > & {
    /** If set, never pick these floor indices as spawn source (teach / special rules). */
    disallowedSourceFloorIndices?: readonly number[];
  },
  rngState: number,
  nextId: number,
): {
  waitingByFloor: Passenger[][];
  nextId: number;
  rngState: number;
  spawned: boolean;
} {
  const nFloors = cfg.floorAltitudes.length;
  const queues = waitingByFloor.map((q) => q.slice());
  const dis = cfg.disallowedSourceFloorIndices;
  let s = rngState >>> 0;

  const roll = (): number => {
    const o = mulberry32Step(s);
    s = o.state;
    return o.u;
  };

  for (let attempt = 0; attempt < SPAWN_ATTEMPTS_MAX; attempt += 1) {
    const sourceFloorIndex = Math.floor(roll() * nFloors);
    if (dis !== undefined && dis.includes(sourceFloorIndex)) {
      continue;
    }
    if (queues[sourceFloorIndex]!.length >= cfg.maxWaitingPerFloor) {
      continue;
    }
    let targetFloorIndex = Math.floor(roll() * nFloors);
    if (nFloors > 1) {
      let guard = 0;
      while (targetFloorIndex === sourceFloorIndex && guard < 32) {
        targetFloorIndex = Math.floor(roll() * nFloors);
        guard += 1;
      }
      if (targetFloorIndex === sourceFloorIndex) {
        continue;
      }
    }
    const archetype = pickArchetype(cfg.allowedPassengerTypes, roll);
    const p = createPassenger(
      nextId,
      sourceFloorIndex,
      targetFloorIndex,
      archetype,
    );
    queues[sourceFloorIndex]!.push(p);
    return {
      waitingByFloor: queues,
      nextId: nextId + 1,
      rngState: s,
      spawned: true,
    };
  }

  return {
    waitingByFloor: queues,
    nextId,
    rngState: s,
    spawned: false,
  };
}
