import type { LevelGameConfig } from "../levelGameConfig.js";
import { level1Game } from "./level1.js";
import { level2Game } from "./level2.js";
import { level3Game } from "./level3.js";
import { level4Game } from "./level4.js";
import { level5Game } from "./level5.js";

/** All Arc 1 levels, index 0 = level 1. */
export const ARC1_CAMPAIGN_LEVELS: readonly LevelGameConfig[] = [
  level1Game,
  level2Game,
  level3Game,
  level4Game,
  level5Game,
] as const;

export function getArc1LevelByIndex(
  i: number,
): LevelGameConfig | undefined {
  if (i < 0 || i >= ARC1_CAMPAIGN_LEVELS.length) {
    return undefined;
  }
  return ARC1_CAMPAIGN_LEVELS[i]!;
}
