/**
 * Browser / WebView host surface. Keeps a single place to read time, rAF, DPR, and `window` for
 * embedded (WKWebView / Android WebView) and plain web dev. Do not use from `src/sim/`.
 */
export function getDevicePixelRatio(): number {
  if (typeof globalThis === "object" && "devicePixelRatio" in globalThis) {
    const d = (globalThis as { devicePixelRatio?: number }).devicePixelRatio;
    if (typeof d === "number" && d > 0) {
      return d;
    }
  }
  return 1;
}

export function getHostTimeMs(): number {
  if (typeof globalThis === "object" && "performance" in globalThis) {
    const p = (globalThis as { performance?: { now: () => number } }).performance;
    if (p && typeof p.now === "function") {
      return p.now();
    }
  }
  return Date.now();
}

/**
 * The visible window. Only available in browser-like hosts (not Vitest’s default node `sim` tests for sim-only modules).
 */
export function getHostWindow(): Window | undefined {
  if (typeof globalThis === "object" && "addEventListener" in globalThis) {
    return globalThis as unknown as Window;
  }
  return undefined;
}

/**
 * @returns `requestAnimationFrame` id, or 0 if unavailable (e.g. non-browser host).
 */
export function hostRequestAnimationFrame(
  frame: (time: number) => void,
): number {
  if (typeof globalThis === "object" && "requestAnimationFrame" in globalThis) {
    return (
      (globalThis as { requestAnimationFrame: (c: (t: number) => void) => number })
        .requestAnimationFrame
    )(frame);
  }
  return 0;
}
