import { floorDockCenterAltitude } from "../sim/docking.js";
import type { LevelGameConfig } from "../config/levelGameConfig.js";

/** Seconds to go from base ↔ max zoom when crossing in/out of a floor band (both directions). */
export const FLOOR_ZOOM_RAMP_SECONDS = 1;
/** `viewHalfSim` is multiplied by this at full ramp; wider FOV = more zoomed out. */
export const FLOOR_MAX_ZOOM_OUT_FACTOR = 1.5;
/**
 * Floor camera zoom-in only when |vertical velocity| (sim / s) is below this, so a fast
 * fly-through does not switch to a tight dock framing.
 */
export const FLOOR_ZOOM_IN_MAX_CAB_SPEED = 30;

/**
 * “Near a floor” for camera ramp: for each floor, a vertical window
 * [dock − 2H, dock + 2H] with H = `elevatorCabHeightSim` (2× the former half-width so
 * ramp-in starts sooner). The host also gates zoom-in on cab speed; see
 * `shouldApplyFloorCameraZoomIn`.
 */
export function isCabInFloorPlusMinusCabHeightZone(
  cabCenterAltitude: number,
  level: Pick<
    LevelGameConfig,
    "floorAltitudes" | "elevatorCabHeightSim" | "floorSlabSim"
  >,
): boolean {
  const halfW = 2 * level.elevatorCabHeightSim;
  for (let i = 0; i < level.floorAltitudes.length; i += 1) {
    const d = floorDockCenterAltitude(i, level);
    if (cabCenterAltitude >= d - halfW && cabCenterAltitude <= d + halfW) {
      return true;
    }
  }
  return false;
}

/**
 * True when the host should ramp toward a zoomed-in floor framing: near a floor in the
 * wide proximity band and moving slowly (dock intent), not a fast pass.
 */
export function shouldApplyFloorCameraZoomIn(
  cabCenterAltitude: number,
  cabVerticalVelocity: number,
  level: Pick<
    LevelGameConfig,
    "floorAltitudes" | "elevatorCabHeightSim" | "floorSlabSim"
  >,
): boolean {
  return (
    isCabInFloorPlusMinusCabHeightZone(cabCenterAltitude, level) &&
    Math.abs(cabVerticalVelocity) < FLOOR_ZOOM_IN_MAX_CAB_SPEED
  );
}

/**
 * @param zoomBlendT 0 = base (zoomed in near a floor), 1 = `maxOutFactor` (most zoomed out).
 */
export function viewHalfSimFromZoomBlend(
  base: number,
  maxOutFactor: number,
  zoomBlendT: number,
): number {
  const t = Math.min(1, Math.max(0, zoomBlendT));
  return base * (1 + (maxOutFactor - 1) * t);
}
