import type { PassengerArchetypeMvp } from "../sim/passenger.js";

/**
 * Waiting-passenger silhouette vs cab — **render** pixel layout (`cabW`/`cabH`).
 * `passengerHeightSim` in level config matches slab+lobby sim span (hover band height).
 * Durations and path segments shared with sim: `transferTiming.ts`.
 */

/** In-cab / platform passenger rectangle fill; keep in sync with `drawPassengerSilhouette`. */
export const PASSENGER_BODY_FILL: Record<PassengerArchetypeMvp, string> = {
  regular: "rgba(148, 163, 184, 0.95)",
  urgent: "rgba(248, 113, 113, 0.95)",
  heavy: "rgba(147, 197, 253, 0.95)",
};

/** Rounded-rect stroke around the passenger body (canvas). */
export const PASSENGER_BODY_STROKE = "rgba(15, 23, 42, 0.65)";

/**
 * Right-HUD floor chips: same body fill and outline family as the cab silhouettes.
 */
export function domCabDestChipStyle(arch: PassengerArchetypeMvp): {
  backgroundColor: string;
  border: string;
  color: string;
} {
  return {
    backgroundColor: PASSENGER_BODY_FILL[arch],
    border: `1.5px solid ${PASSENGER_BODY_STROKE}`,
    color: "#0f172a",
  };
}

export const PAX_HEIGHT_FRAC_OF_CAB = 0.58;
export const PAX_WIDTH_FRAC_OF_CAB = 0.26;

/** Cab body fill alpha (glass over in-cab silhouettes). */
export const CAB_GLASS_FILL_ALPHA = 0.18;
