/**
 * Shared geometry and Arc 1 docking defaults. Per-level floor arrays and world bounds
 * are composed in `src/config/arc1/level1.ts` … `level5.ts` (and `levelGameConfig.ts` for
 * the combined `LevelGameConfig` type).
 */
export const ELEVATOR_CAB_HEIGHT_SIM = 16;
export const ELEVATOR_CAB_WIDTH_SIM = 14;
export const FLOOR_SLAB_SIM = 4;
export const LOBBY_HEIGHT_MUL = 1.35;
export const LOBBY_HEIGHT_SIM = ELEVATOR_CAB_HEIGHT_SIM * LOBBY_HEIGHT_MUL;
/** 10× cab height — default spacing between floor bases. */
export const FLOOR_STEP_SIM = 160;
export const FAILURE_MARGIN_ABOVE_TOP_FLOOR = FLOOR_STEP_SIM;
export const DESIGN_VIEW_HALF_SIM = 57.5;

/** L2–L5: same as former single-level prototype defaults. */
export const arc1DockingDefault = {
  dockingVelocityThreshold: 10.0,
  hoverBreakGraceSeconds: 0.2,
  doorAutoCloseIdleSeconds: 0.4,
  stableHoverSeconds: 2,
} as const;

/** Level 1 only: easier to satisfy hover and transfers. */
export const arc1DockingLooseL1 = {
  dockingVelocityThreshold: 12.0,
  hoverBreakGraceSeconds: 0.35,
  doorAutoCloseIdleSeconds: 0.4,
  stableHoverSeconds: 1.5,
} as const;

/** Return shape of `buildArc1Layout` (world geometry + view bounds for one stage). */
export type Arc1Layout = {
  elevatorCabHeightSim: number;
  elevatorCabWidthSim: number;
  floorSlabSim: number;
  lobbyHeightMul: number;
  lobbyHeightSim: number;
  floorAltitudes: readonly number[];
  maxFloorAltitude: number;
  failureMarginAboveTopFloor: number;
  failureAltitude: number;
  extentMaxAltitude: number;
  gravityBlendStartAltitude: number;
  gravityBlendEndAltitude: number;
  viewHalfSim: number;
  viewHalfSimBase: number;
  startAltitude: number;
};

/**
 * Per-level world layout. Keep `gravityBlend*` and `extentMaxAltitude` in sync for tall shafts.
 */
export function buildArc1Layout(
  floorAltitudes: readonly number[],
  world: {
    extentMaxAltitude: number;
    gravityBlendStartAltitude: number;
    gravityBlendEndAltitude: number;
  },
  viewHalfSim: number = DESIGN_VIEW_HALF_SIM,
): Arc1Layout {
  const maxFloorAltitude = Math.max(...floorAltitudes);
  return {
    elevatorCabHeightSim: ELEVATOR_CAB_HEIGHT_SIM,
    elevatorCabWidthSim: ELEVATOR_CAB_WIDTH_SIM,
    floorSlabSim: FLOOR_SLAB_SIM,
    lobbyHeightMul: LOBBY_HEIGHT_MUL,
    lobbyHeightSim: LOBBY_HEIGHT_SIM,
    floorAltitudes: [...floorAltitudes],
    maxFloorAltitude,
    failureMarginAboveTopFloor: FAILURE_MARGIN_ABOVE_TOP_FLOOR,
    failureAltitude: maxFloorAltitude + FAILURE_MARGIN_ABOVE_TOP_FLOOR,
    extentMaxAltitude: world.extentMaxAltitude,
    gravityBlendStartAltitude: world.gravityBlendStartAltitude,
    gravityBlendEndAltitude: world.gravityBlendEndAltitude,
    viewHalfSim,
    viewHalfSimBase: viewHalfSim,
    startAltitude:
      floorAltitudes[0]! + FLOOR_SLAB_SIM + ELEVATOR_CAB_HEIGHT_SIM / 2,
  };
}
