import type { PhysicsConfig } from "../config/physics.js";
import type { ElevatorState } from "./types.js";

export function createInitialState(
  config: PhysicsConfig,
  startAltitude?: number,
): ElevatorState {
  const altitude =
    startAltitude ??
    (config.worldMinAltitude + config.levelMaxAltitude) / 2;
  return {
    altitude,
    velocity: 0,
    acceleration: 0,
    thrustActive: false,
    mass: config.baseMass,
  };
}

/** One physics substep: floor collision, before velocity clamp, downward speed (sim/s). */
export type GroundImpact = {
  hitGround: boolean;
  impactSpeedDown: number;
};

/**
 * One fixed-timestep integration (semi-implicit Euler).
 * Uses `state.mass` (base + passengers); callers sync mass from onboard after boarding changes.
 * @param gravityEffective downward acceleration magnitude (sim units / s²), already includes altitude curve.
 */
export function stepElevator(
  state: ElevatorState,
  thrustActive: boolean,
  config: PhysicsConfig,
  dt: number,
  gravityEffective: number,
): { state: ElevatorState; impact: GroundImpact } {
  const mass = Math.max(config.baseMass * 0.25, state.mass);
  const thrustAccel = thrustActive ? config.thrustForce / mass : 0;
  let accel = thrustAccel - gravityEffective;
  if (config.linearDrag > 0) {
    accel -= config.linearDrag * state.velocity;
  }

  let velocity = state.velocity + accel * dt;
  let altitude = state.altitude + velocity * dt;

  let hitGround = false;
  let impactSpeedDown = 0;
  if (altitude <= config.worldMinAltitude) {
    altitude = config.worldMinAltitude;
    if (velocity < 0) {
      hitGround = true;
      impactSpeedDown = -velocity;
      velocity = 0;
    }
  }

  return {
    state: {
      altitude,
      velocity,
      acceleration: accel,
      thrustActive,
      mass,
    },
    impact: { hitGround, impactSpeedDown },
  };
}
